'use client';

import { Sidebar } from '@/components/admin/Sidebar';
import { useStore } from '@/lib/store';
import { useRouter } from 'next/navigation';
import { useEffect, useState } from 'react';
import { supabase } from '@/lib/supabaseClient';
import { Broker, Property } from '@/lib/types';
import { Suspense } from 'react';
import { Menu } from 'lucide-react';
import { Logo } from '@/components/ui/Logo';
import { Button } from '@/components/ui/Button';
import { cn } from '@/lib/utils';

export default function AdminLayout({
    children,
}: {
    children: React.ReactNode;
}) {
    const { isAdmin, hasHydrated, setBrokers, setProperties } = useStore();
    const router = useRouter();
    const [mounted, setMounted] = useState(false);
    const [isSidebarOpen, setIsSidebarOpen] = useState(false);

    useEffect(() => {
        setMounted(true);
    }, []);

    useEffect(() => {
        if (hasHydrated && mounted) {
            if (!isAdmin) {
                // router.push('/login');
            }
        }
    }, [isAdmin, router, hasHydrated, mounted]);

    // Fetch data centrally for all admin sub-pages
    useEffect(() => {
        if (!isAdmin || !mounted || !hasHydrated) return;

        const fetchData = async () => {
            try {
                // Fetch Brokers
                const { data: brokerData, error: brokerError } = await supabase
                    .from('profiles')
                    .select('*')
                    .order('registered_at', { ascending: false });

                if (brokerError) {
                    console.error('Error fetching brokers from Supabase:', brokerError);
                } else if (brokerData) {
                    console.log(`Fetched ${brokerData.length} brokers for Admin Panel`);
                    const mappedBrokers: Broker[] = brokerData.map((b: { id: string; name?: string; email?: string; phone?: string; broker_code?: string; rera_number?: string; districts?: string[]; city?: string; village?: string; status?: 'pending' | 'approved' | 'rejected'; registered_at?: string; subscription_expiry?: string; referral_code?: string; referred_by?: string; referral_count?: number; referrals_count?: number; referral_earnings?: number; unique_broker_id?: string; company_name?: string; designation?: string; whatsapp_number?: string; }) => ({
                        id: b.id,
                        name: b.name || 'Unknown',
                        email: b.email || '',
                        phone: b.phone || '',
                        broker_code: b.broker_code || '',
                        role: 'broker',
                        reraNumber: b.rera_number,
                        districts: b.districts || [],
                        city: b.city,
                        village: b.village,
                        status: b.status || 'pending',
                        registeredAt: b.registered_at || new Date().toISOString(),
                        subscriptionExpiry: b.subscription_expiry || new Date().toISOString(),
                        referralCode: b.referral_code || '',
                        referredBy: b.referred_by,
                        referralCount: b.referral_count || b.referrals_count || 0,
                        referralEarnings: b.referral_earnings || 0,
                        uniqueBrokerId: b.unique_broker_id || `PD-UNASSIGNED-${b.id.substring(0, 4)}`,
                        companyName: b.company_name,
                        designation: b.designation,
                        whatsappNumber: b.whatsapp_number,
                    }));
                    setBrokers(mappedBrokers);
                }

                // Fetch Properties
                const { data: propertyData, error: propertyError } = await supabase
                    .from('properties')
                    .select('*')
                    .order('created_at', { ascending: false });

                if (propertyError) {
                    console.error('Error fetching properties:', propertyError);
                } else if (propertyData) {
                    const mappedProperties: Property[] = propertyData.map((p: { id: string; broker_id: string; title?: string; description?: string; price?: number; district?: string; location?: string; type?: 'sale' | 'rent' | 'lease'; category?: string; images?: string[]; created_at: string; updated_at: string; expires_at: string; is_active?: boolean; likes?: number; leads_count?: number; amenities?: string[]; }) => ({
                        id: p.id,
                        brokerId: p.broker_id,
                        title: p.title || 'No Title',
                        description: p.description || '',
                        price: p.price || 0,
                        district: p.district || 'Unknown',
                        location: p.location || 'Unknown',
                        type: p.type || 'sale',
                        category: (p.category as any) || 'residential',
                        images: p.images || [],
                        createdAt: p.created_at,
                        updatedAt: p.updated_at,
                        expiresAt: p.expires_at,
                        isActive: p.is_active ?? true,
                        likes: p.likes || 0,
                        leadsCount: p.leads_count || 0,
                        amenities: p.amenities || [],
                    }));
                    setProperties(mappedProperties);
                }
            } catch (err) {
                console.error("Critical error fetching admin data:", err);
            }
        };

        fetchData();
    }, [isAdmin, mounted, hasHydrated, setBrokers, setProperties]);

    if (!mounted || !hasHydrated) {
        return (
            <div className="min-h-screen flex items-center justify-center bg-gray-50 dark:bg-gray-950">
                <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary"></div>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-gray-100 dark:bg-gray-950 flex flex-col">
            {/* Mobile Header */}
            <header className="lg:hidden bg-gray-900 text-white h-16 px-4 flex items-center justify-between sticky top-0 z-[40] shadow-md">
                <div className="flex items-center">
                    <Logo
                        showTagline={false}
                        iconClassName="h-6 w-6"
                        textClassName="text-lg text-white"
                        className="mr-2"
                    />
                </div>
                <Button variant="ghost" size="icon" onClick={() => setIsSidebarOpen(true)} className="text-gray-400 hover:text-white">
                    <Menu className="h-6 w-6" />
                </Button>
            </header>

            <div className="flex flex-1 relative overflow-hidden">
                {/* Backdrop for mobile */}
                {isSidebarOpen && (
                    <div
                        className="fixed inset-0 bg-black/60 z-[50] lg:hidden backdrop-blur-sm transition-opacity"
                        onClick={() => setIsSidebarOpen(false)}
                    />
                )}

                <Suspense fallback={<div className="w-64 bg-gray-900 hidden lg:block" />}>
                    <Sidebar isOpen={isSidebarOpen} onClose={() => setIsSidebarOpen(false)} />
                </Suspense>

                <main className={cn(
                    "flex-1 p-4 md:p-8 overflow-y-auto h-[calc(100vh-64px)] lg:h-screen transition-all duration-300",
                    "lg:ml-64" // Content push on desktop
                )}>
                    <Suspense fallback={<div className="flex items-center justify-center h-full">
                        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary"></div>
                    </div>}>
                        <div className="lg:hidden mb-6 bg-white dark:bg-gray-900 p-4 rounded-xl border border-gray-200 dark:border-gray-800 shadow-sm">
                            <h1 className="text-xl font-bold text-gray-900 dark:text-white">Admin Panel</h1>
                            <p className="text-xs text-gray-500">Karnataka&apos;s Verified Broker Network</p>
                        </div>
                        {children}
                    </Suspense>
                </main>
            </div>
        </div >
    );
}

'use client';

import { useState, useEffect } from 'react';
import { useStore } from '@/lib/store';
import { Button } from '@/components/ui/Button';
import { Input } from '@/components/ui/Input';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/Card';
import { Save, Trash2, Settings, Image as ImageIcon } from 'lucide-react';
import { SiteConfig } from '@/lib/types';
import { toast } from 'sonner';
import { supabase } from '@/lib/supabaseClient';
import { LogoSettings } from '@/components/admin/LogoSettings';

export default function SettingsPage() {
    const { siteConfig, fetchSiteConfig, updateSiteConfig } = useStore();
    const [config, setConfig] = useState<SiteConfig | null>(null);
    const [loading, setLoading] = useState(false);
    const [activeTab, setActiveTab] = useState<'general' | 'branding'>('general');

    useEffect(() => {
        fetchSiteConfig();
    }, [fetchSiteConfig]);

    useEffect(() => {
        if (siteConfig) {
            setConfig(siteConfig);
        }
    }, [siteConfig]);

    const handleChange = (field: keyof SiteConfig, value: string) => {
        if (!config) return;
        setConfig({ ...config, [field]: value });
    };

    const handleSocialChange = (field: keyof SiteConfig['socialLinks'], value: string) => {
        if (!config) return;
        setConfig({
            ...config,
            socialLinks: { ...config.socialLinks, [field]: value }
        });
    };


    const handleSave = async () => {
        if (!config) return;
        setLoading(true);
        try {
            await updateSiteConfig(config);
            toast.success('Settings updated successfully!');
        } catch (error) {
            toast.error('Failed to update settings');
        } finally {
            setLoading(false);
        }
    };

    const handleClearData = async () => {
        const password = confirm("CRITICAL: You are about to clear ALL property and broker data. This cannot be undone.");
        if (!password) return;

        const confirmation = prompt("Please type 'CLEARDATA' to proceed:");
        if (confirmation !== 'CLEARDATA') {
            toast.error("Cleanup cancelled. Confirmation text did not match.");
            return;
        }

        toast.loading("Clearing data...");

        // Delete all properties first
        const { error: propError } = await supabase.from('properties').delete().neq('id', '00000000-0000-0000-0000-000000000000');
        if (propError) console.error("Error clearing properties:", propError);

        // Delete all non-admin profiles
        const { error: profileError } = await supabase
            .from('profiles')
            .delete()
            .neq('is_admin', true);

        if (profileError) console.error("Error clearing profiles:", profileError);

        toast.dismiss();
        toast.success("Client data cleared. Admin accounts preserved.");
        window.location.reload();
    };

    if (!config) return <div className="p-8">Loading settings...</div>;

    return (
        <div className="space-y-6 max-w-4xl">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-3xl font-bold">Site Management</h1>
                    <p className="text-muted-foreground text-sm">Configure your website appearance and settings.</p>
                </div>
                {activeTab === 'general' && (
                    <Button onClick={handleSave} disabled={loading} className="gap-2 shadow-lg shadow-primary/20">
                        <Save className="h-4 w-4" /> Save General Settings
                    </Button>
                )}
            </div>

            {/* Tab Navigation */}
            <div className="flex items-center gap-2 p-1 bg-muted/50 rounded-lg w-fit">
                <Button
                    variant={activeTab === 'general' ? 'default' : 'ghost'}
                    size="sm"
                    onClick={() => setActiveTab('general')}
                    className="gap-2"
                >
                    <Settings className="h-4 w-4" /> General Settings
                </Button>
                <Button
                    variant={activeTab === 'branding' ? 'default' : 'ghost'}
                    size="sm"
                    onClick={() => setActiveTab('branding')}
                    className="gap-2"
                >
                    <ImageIcon className="h-4 w-4" /> Logo & Branding
                </Button>
            </div>

            <div className="grid gap-6">
                {activeTab === 'branding' ? (
                    <LogoSettings />
                ) : (
                    <>
                        <Card>
                            <CardHeader>
                                <CardTitle>Hero Section</CardTitle>
                            </CardHeader>
                            <CardContent className="space-y-4">
                                <div className="space-y-2">
                                    <label className="text-sm font-medium">Hero Custom Title</label>
                                    <Input
                                        value={config.heroTitle}
                                        onChange={(e) => handleChange('heroTitle', e.target.value)}
                                    />
                                </div>
                                <div className="space-y-2">
                                    <label className="text-sm font-medium">Hero Description</label>
                                    <textarea
                                        className="flex w-full rounded-md border border-input bg-transparent px-3 py-2 text-sm shadow-sm min-h-[80px]"
                                        value={config.heroDescription}
                                        onChange={(e) => handleChange('heroDescription', e.target.value)}
                                    />
                                </div>
                                <div className="space-y-2">
                                    <label className="text-sm font-medium">Hero Background Image URL</label>
                                    <Input
                                        value={config.heroBackgroundImage}
                                        onChange={(e) => handleChange('heroBackgroundImage', e.target.value)}
                                    />
                                </div>
                            </CardContent>
                        </Card>

                        <Card>
                            <CardHeader>
                                <CardTitle>Footer & Contact</CardTitle>
                            </CardHeader>
                            <CardContent className="space-y-4">
                                <div className="space-y-2">
                                    <label className="text-sm font-medium">Footer Copyright Text</label>
                                    <Input
                                        value={config.footerText}
                                        onChange={(e) => handleChange('footerText', e.target.value)}
                                    />
                                </div>
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                    <div className="space-y-2">
                                        <label className="text-sm font-medium">Contact Phone</label>
                                        <Input
                                            value={config.contactPhone}
                                            onChange={(e) => handleChange('contactPhone', e.target.value)}
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <label className="text-sm font-medium">Contact Email</label>
                                        <Input
                                            value={config.contactEmail}
                                            onChange={(e) => handleChange('contactEmail', e.target.value)}
                                        />
                                    </div>
                                </div>
                                <div className="space-y-2 pt-2">
                                    <label className="text-sm font-medium">Office Address</label>
                                    <textarea
                                        className="flex w-full rounded-md border border-input bg-transparent px-3 py-2 text-sm shadow-sm min-h-[100px] focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring"
                                        value={config.officeAddress || ''}
                                        onChange={(e) => handleChange('officeAddress', e.target.value)}
                                        placeholder="Enter full office address..."
                                    />
                                </div>
                            </CardContent>
                        </Card>


                        <Card>
                            <CardHeader>
                                <CardTitle>Social Media Links</CardTitle>
                            </CardHeader>
                            <CardContent className="grid gap-4 md:grid-cols-2">
                                <div className="space-y-2">
                                    <label className="text-sm font-medium">Facebook</label>
                                    <Input
                                        value={config.socialLinks.facebook || ''}
                                        onChange={(e) => handleSocialChange('facebook', e.target.value)}
                                        placeholder="#"
                                    />
                                </div>
                                <div className="space-y-2">
                                    <label className="text-sm font-medium">Twitter / X</label>
                                    <Input
                                        value={config.socialLinks.twitter || ''}
                                        onChange={(e) => handleSocialChange('twitter', e.target.value)}
                                        placeholder="#"
                                    />
                                </div>
                                <div className="space-y-2">
                                    <label className="text-sm font-medium">Instagram</label>
                                    <Input
                                        value={config.socialLinks.instagram || ''}
                                        onChange={(e) => handleSocialChange('instagram', e.target.value)}
                                        placeholder="#"
                                    />
                                </div>
                                <div className="space-y-2">
                                    <label className="text-sm font-medium">LinkedIn</label>
                                    <Input
                                        value={config.socialLinks.linkedin || ''}
                                        onChange={(e) => handleSocialChange('linkedin', e.target.value)}
                                        placeholder="#"
                                    />
                                </div>
                            </CardContent>
                        </Card>

                        <Card className="border-red-200 bg-red-50/10">
                            <CardHeader>
                                <div className="flex items-center gap-2 text-red-600">
                                    <Trash2 className="h-5 w-5" />
                                    <CardTitle className="text-lg">Danger Zone</CardTitle>
                                </div>
                            </CardHeader>
                            <CardContent>
                                <p className="text-sm text-muted-foreground mb-4">
                                    Clearing all data will permanently remove all property listings and non-admin broker profiles.
                                </p>
                                <Button
                                    variant="destructive"
                                    onClick={handleClearData}
                                    className="bg-red-600 hover:bg-red-700 font-bold"
                                >
                                    Reset Application Data
                                </Button>
                            </CardContent>
                        </Card>
                    </>
                )}
            </div>
        </div>
    );
}

