            if (propData) {
                const mappedProperty: Property = {
                    id: propData.id,
                    brokerId: propData.broker_id,
                    title: propData.title,
                    description: propData.description,
                    price: propData.price,
                    district: propData.district,
                    location: propData.location,
                    village: propData.village,
                    type: propData.type,
                    category: propData.category,
                    images: propData.images,
                    createdAt: propData.created_at,
                    updatedAt: propData.updated_at,
                    expiresAt: propData.expires_at,
                    isActive: propData.is_active,
                    likes: propData.likes,
                    leadsCount: propData.leads_count,
                    amenities: propData.facilities || [], // Map facilities from DB to amenities for UI
                    structureType: propData.structure_type,
                    parkingSpaces: propData.parking_spaces,
                    parkingType: propData.parking_type,
                    googleMapLink: propData.google_map_link,
                    hidePrice: propData.hide_price,
                    brokerPhone: propData.broker_phone
                };
                setProperty(mappedProperty);

                // Fetch Broker for this property
                const { data: brokerData, error: brokerError } = await supabase
                    .from('profiles')
                    .select('*')
                    .eq('id', propData.broker_id)
                    .single();

                if (brokerData) {
                    const mappedBroker: Broker = {
                        id: brokerData.id,
                        name: brokerData.name,
                        email: brokerData.email,
                        phone: brokerData.phone,
                        broker_code: brokerData.broker_code,
                        role: 'broker',
                        districts: brokerData.districts || [],
                        status: brokerData.status,
                        registeredAt: brokerData.registered_at,
                        subscriptionExpiry: brokerData.subscription_expiry,
                        referralCode: brokerData.referral_code,
                        referralCount: brokerData.referral_count || brokerData.referrals_count || 0,
                        uniqueBrokerId: brokerData.unique_broker_id || `PD-UNASSIGNED-${brokerData.id.substring(0, 4)}`,
                        referralEarnings: brokerData.referral_earnings || 0
                    };
                    setBroker(mappedBroker);
                }
            }
            setLoading(false);
        };

        fetchProperty();
