    const handleLeadSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!leadForm.name || !leadForm.phone) {
            toast.error('Please fill in your name and phone number.');
            return;
        }

        addPropertyLead({
            id: `lead-${Date.now()}`,
            propertyId: property.id,
            brokerId: property.brokerId,
