'use client';

import React, { useState, useEffect, useCallback } from 'react';
import useEmblaCarousel from 'embla-carousel-react';
import { Badge } from './ui/Badge';
import { Button } from './ui/Button';
import { ChevronLeft, ChevronRight } from 'lucide-react';

interface PropertyImageGalleryProps {
    images: string[];
    title: string;
}

export function PropertyImageGallery({ images, title }: PropertyImageGalleryProps) {
    const [selectedIndex, setSelectedIndex] = useState(0);
    const [emblaMainRef, emblaMainApi] = useEmblaCarousel({ loop: true });
    const [emblaThumbsRef, emblaThumbsApi] = useEmblaCarousel({
        containScroll: 'keepSnaps',
        dragFree: true,
    });

    const onThumbClick = useCallback(
        (index: number) => {
            if (!emblaMainApi || !emblaThumbsApi) return;
            emblaMainApi.scrollTo(index);
        },
        [emblaMainApi, emblaThumbsApi]
    );

    const onSelect = useCallback(() => {
        if (!emblaMainApi || !emblaThumbsApi) return;
        setSelectedIndex(emblaMainApi.selectedScrollSnap());
        emblaThumbsApi.scrollTo(emblaMainApi.selectedScrollSnap());
    }, [emblaMainApi, emblaThumbsApi]);

    useEffect(() => {
        if (!emblaMainApi) return;
        onSelect();
        emblaMainApi.on('select', onSelect);
        emblaMainApi.on('reInit', onSelect);
    }, [emblaMainApi, onSelect]);

    if (!images || images.length === 0) return null;

    return (
        <div className="space-y-4">
            {/* Main Carousel */}
            <div className="relative group overflow-hidden rounded-2xl border-4 border-white shadow-xl bg-gray-100 dark:bg-gray-800 aspect-[16/9]">
                <div className="overflow-hidden h-full" ref={emblaMainRef}>
                    <div className="flex h-full">
                        {images.map((src, index) => (
                            <div className="flex-[0_0_100%] min-w-0 relative h-full" key={index}>
                                <img
                                    src={src}
                                    alt={`${title} - Image ${index + 1}`}
                                    className="block w-full h-full object-cover"
                                />
                            </div>
                        ))}
                    </div>
                </div>

                {/* Navigation Buttons */}
                <Button
                    variant="outline"
                    size="icon"
                    className="absolute left-4 top-1/2 -translate-y-1/2 opacity-0 group-hover:opacity-100 transition-opacity bg-white/80 hover:bg-white border-none shadow-lg rounded-full"
                    onClick={() => emblaMainApi?.scrollPrev()}
                >
                    <ChevronLeft className="h-6 w-6" />
                </Button>
                <Button
                    variant="outline"
                    size="icon"
                    className="absolute right-4 top-1/2 -translate-y-1/2 opacity-0 group-hover:opacity-100 transition-opacity bg-white/80 hover:bg-white border-none shadow-lg rounded-full"
                    onClick={() => emblaMainApi?.scrollNext()}
                >
                    <ChevronRight className="h-6 w-6" />
                </Button>

                <div className="absolute top-4 left-4">
                    <Badge className="bg-black/50 backdrop-blur-md border-none px-3 py-1 text-white">
                        {selectedIndex + 1} / {images.length} Photos
                    </Badge>
                </div>
            </div>

            {/* Thumbnails */}
            <div className="overflow-hidden px-1" ref={emblaThumbsRef}>
                <div className="flex gap-4">
                    {images.map((src, index) => (
                        <div
                            key={index}
                            className={`relative flex-[0_0_20%] min-w-0 cursor-pointer rounded-xl overflow-hidden aspect-[4/3] border-2 transition-all duration-300 ${index === selectedIndex ? 'border-primary ring-2 ring-primary/30 scale-105' : 'border-transparent opacity-70 hover:opacity-100'
                                }`}
                            onClick={() => onThumbClick(index)}
                        >
                            <img
                                src={src}
                                alt={`Thumbnail ${index + 1}`}
                                className="w-full h-full object-cover"
                            />
                        </div>
                    ))}
                </div>
            </div>
        </div>
    );
}

'use client';

import { useState } from 'react';
import { Input } from '@/components/ui/Input';
import { Button } from '@/components/ui/Button';
import { Search, Filter, X } from 'lucide-react';

interface PropertySearchProps {
    onSearch: (filters: SearchFilters) => void;
}

export interface SearchFilters {
    district: string;
    city: string; // matches 'location' in Property type
    village: string;
    agentName: string;
}

export function PropertySearch({ onSearch }: PropertySearchProps) {
    const [filters, setFilters] = useState<SearchFilters>({
        district: '',
        city: '',
        village: '',
        agentName: '',
    });
    const [isOpen, setIsOpen] = useState(false);

    const handleSearch = () => {
        onSearch(filters);
    };

    const handleClear = () => {
        const resetFilters = { district: '', city: '', village: '', agentName: '' };
        setFilters(resetFilters);
        onSearch(resetFilters);
    };

    const handleChange = (key: keyof SearchFilters, value: string) => {
        setFilters(prev => ({ ...prev, [key]: value }));
    };

    return (
        <div className="w-full max-w-4xl mx-auto -mt-8 relative z-20 px-4">
            <div className="bg-white dark:bg-gray-800 rounded-xl shadow-xl border border-gray-100 dark:border-gray-700 p-4 md:p-6">
                <div className="flex flex-col md:flex-row gap-4">
                    {/* Main Search Bar - Desktop: Agent/District, Mobile: Toggle key fields */}
                    <div className="flex-1 grid grid-cols-1 md:grid-cols-4 gap-4">
                        <div className="md:col-span-1">
                            <Input
                                placeholder="District..."
                                value={filters.district}
                                onChange={(e) => handleChange('district', e.target.value)}
                                className="bg-gray-50 border-gray-200"
                            />
                        </div>
                        <div className="md:col-span-1">
                            <Input
                                placeholder="City / Area..."
                                value={filters.city}
                                onChange={(e) => handleChange('city', e.target.value)}
                                className="bg-gray-50 border-gray-200"
                            />
                        </div>
                        <div className="md:col-span-1">
                            <Input
                                placeholder="Local Area/Village..."
                                value={filters.village}
                                onChange={(e) => handleChange('village', e.target.value)}
                                className="bg-gray-50 border-gray-200"
                            />
                        </div>
                        <div className="md:col-span-1">
                            <Input
                                placeholder="Agent Name..."
                                value={filters.agentName}
                                onChange={(e) => handleChange('agentName', e.target.value)}
                                className="bg-gray-50 border-gray-200"
                            />
                        </div>
                    </div>

                    <div className="flex gap-2 shrink-0">
                        <Button onClick={handleSearch} className="flex-1 md:w-auto font-bold shadow-lg shadow-primary/25">
                            <Search className="h-4 w-4 mr-2" /> Search
                        </Button>
                        {(filters.district || filters.city || filters.village || filters.agentName) && (
                            <Button variant="ghost" size="icon" onClick={handleClear} className="text-gray-500 hover:text-red-500">
                                <X className="h-4 w-4" />
                            </Button>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
}

'use client';

import { useState } from 'react';
import { Input } from '@/components/ui/Input';
import { Button } from '@/components/ui/Button';
import { Search, MapPin, Building, User, X } from 'lucide-react';
import { Badge } from '@/components/ui/Badge';

export interface SmartSearchFilters {
    searchBy: 'city' | 'district' | 'village' | 'agent';
    query: string;
    propertyType: string;
}

interface SmartSearchFormProps {
    onSearch: (filters: SmartSearchFilters) => void;
    initialFilters?: Partial<SmartSearchFilters>;
    className?: string;
}

export const PROPERTY_TYPES = [
    'Residential',
    'Commercial',
    'Villa',
    'Apartment',
    'Offices',
    'Farmhouse',
    'Land',
    'Godown'
];

export function SmartSearchForm({ onSearch, initialFilters, className = "" }: SmartSearchFormProps) {
    const [filters, setFilters] = useState<SmartSearchFilters>({
        searchBy: initialFilters?.searchBy || 'city',
        query: initialFilters?.query || '',
        propertyType: initialFilters?.propertyType || '',
    });

    const handleSearch = (e?: React.FormEvent) => {
        if (e) e.preventDefault();
        onSearch(filters);
    };

    return (
        <form
            onSubmit={handleSearch}
            className={`w-full max-w-5xl mx-auto bg-white dark:bg-gray-900 rounded-2xl shadow-2xl border border-gray-100 dark:border-gray-800 p-2 md:p-3 ${className}`}
        >
            <div className="flex flex-col lg:flex-row items-stretch gap-2">
                {/* Search By Dropdown */}
                <div className="flex-1 lg:flex-[0.8] relative group">
                    <label className="absolute left-3 top-1 text-[10px] font-bold text-gray-400 uppercase tracking-tight">Search by</label>
                    <select
                        value={filters.searchBy}
                        onChange={(e) => setFilters(prev => ({ ...prev, searchBy: e.target.value as any }))}
                        className="w-full h-14 pl-3 pr-8 pt-4 bg-gray-50 dark:bg-gray-800/50 border-none rounded-xl text-sm font-semibold focus:ring-2 focus:ring-primary/20 transition-all appearance-none cursor-pointer"
                    >
                        <option value="city">City / Town</option>
                        <option value="district">District</option>
                        <option value="village">Local Area / Village</option>
                        <option value="agent">Agent Name</option>
                    </select>
                    <div className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none text-gray-400">
                        <MapPin className="h-4 w-4" />
                    </div>
                </div>

                {/* Query Input */}
                <div className="flex-[2] relative group">
                    <label className="absolute left-3 top-1 text-[10px] font-bold text-gray-400 uppercase tracking-tight">Enter Details</label>
                    <Input
                        value={filters.query}
                        onChange={(e) => setFilters(prev => ({ ...prev, query: e.target.value }))}
                        placeholder={
                            filters.searchBy === 'city' ? "Which city?" :
                                filters.searchBy === 'district' ? "Which district?" :
                                    filters.searchBy === 'village' ? "Which area/village?" : "Agent name..."
                        }
                        className="w-full h-14 pl-3 pt-4 bg-gray-50 dark:bg-gray-800/50 border-none rounded-xl text-sm font-semibold focus:ring-2 focus:ring-primary/20 transition-all"
                    />
                    {filters.query && (
                        <button
                            type="button"
                            onClick={() => setFilters(prev => ({ ...prev, query: '' }))}
                            className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600 transition-colors"
                        >
                            <X className="h-4 w-4" />
                        </button>
                    )}
                </div>

                {/* Property Type Dropdown */}
                <div className="flex-1 lg:flex-[0.8] relative group">
                    <label className="absolute left-3 top-1 text-[10px] font-bold text-gray-400 uppercase tracking-tight">Property Type</label>
                    <select
                        value={filters.propertyType}
                        onChange={(e) => setFilters(prev => ({ ...prev, propertyType: e.target.value }))}
                        className="w-full h-14 pl-3 pr-8 pt-4 bg-gray-50 dark:bg-gray-800/50 border-none rounded-xl text-sm font-semibold focus:ring-2 focus:ring-primary/20 transition-all appearance-none cursor-pointer"
                    >
                        <option value="">Any Type</option>
                        {PROPERTY_TYPES.map(type => (
                            <option key={type} value={type}>{type}</option>
                        ))}
                    </select>
                    <div className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none text-gray-400">
                        <Building className="h-4 w-4" />
                    </div>
                </div>

                {/* Search Button */}
                <Button
                    type="submit"
                    className="h-14 lg:px-8 rounded-xl bg-primary hover:bg-primary/95 text-white font-bold text-lg shadow-lg shadow-primary/20 transition-all hover:scale-[1.02] active:scale-[0.98] w-full lg:w-auto mt-2 lg:mt-0"
                >
                    <Search className="h-5 w-5 mr-2" />
                    Search
                </Button>
            </div>
        </form>
    );
}

'use client';

import { useState } from 'react';
import { useStore } from '@/lib/store';
import { LogoConfig, IconConfig } from '@/lib/types';
import { Button } from '@/components/ui/Button';
import { Input } from '@/components/ui/Input';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/Card';
import { Logo } from '@/components/ui/Logo';
import { supabase } from '@/lib/supabaseClient';
import { toast } from 'sonner';
import { Upload, Trash2, Image as ImageIcon, Type, RefreshCw } from 'lucide-react';

export function LogoSettings() {
    const { siteConfig, updateSiteConfig } = useStore();
    const [isLoading, setIsLoading] = useState(false);

    // Local state for temporary changes before saving
    const [logo, setLogo] = useState<LogoConfig>(siteConfig.logo || {
        type: 'text',
        text: 'Property Dosti',
        tagline: "Broker's virtual Office",
        fontSize: 24,
        color: '#0f172a'
    });

    const [icon, setIcon] = useState<IconConfig>(siteConfig.icon || {
        type: 'default'
    });

    const handleSave = async () => {
        setIsLoading(true);
        try {
            await updateSiteConfig({
                ...siteConfig,
                logo,
                icon
            });
            toast.success('Logo settings saved successfully!');
        } catch (error) {
            toast.error('Failed to save logo settings');
        } finally {
            setIsLoading(false);
        }
    };

    const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>, target: 'logo' | 'icon') => {
        const file = e.target.files?.[0];
        if (!file) return;

        // Validation
        const validTypes = ['image/png', 'image/jpeg', 'image/jpg', 'image/svg+xml'];
        if (!validTypes.includes(file.type)) {
            toast.error('Please upload a valid image (PNG, JPG, or SVG)');
            return;
        }

        if (file.size > 2 * 1024 * 1024) {
            toast.error('Image size should be less than 2MB');
            return;
        }

        setIsLoading(true);
        try {
            const fileExt = file.name.split('.').pop();
            const fileName = `${target}_${Math.random().toString(36).substring(2)}.${fileExt}`;
            const filePath = `branding/${fileName}`;

            const { error: uploadError } = await supabase.storage
                .from('site-assets')
                .upload(filePath, file);

            if (uploadError) throw uploadError;

            const { data: { publicUrl } } = supabase.storage
                .from('site-assets')
                .getPublicUrl(filePath);

            if (target === 'logo') {
                setLogo({ ...logo, type: 'image', imageUrl: publicUrl });
            } else {
                setIcon({ ...icon, type: 'image', imageUrl: publicUrl });
            }

            toast.success(`${target === 'logo' ? 'Logo' : 'Icon'} uploaded! Remember to Save Changes.`);
        } catch (error: any) {
            console.error('Error uploading:', error);
            toast.error('Failed to upload image');
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="space-y-8">
            {/* Live Preview Section */}
            <Card className="bg-muted/30 border-dashed border-2">
                <CardHeader>
                    <CardTitle className="text-sm font-medium flex items-center gap-2">
                        <RefreshCw className="h-4 w-4" /> Live Header Preview
                    </CardTitle>
                </CardHeader>
                <CardContent className="flex justify-center p-8 bg-white dark:bg-gray-900 rounded-b-xl border-t">
                    <div className="scale-125 transform transition-all duration-300">
                        {/* We use a mockup div to simulate the header context if needed, but Logo is enough */}
                        <div className="p-4 border rounded shadow-sm bg-background">
                            <Logo
                                className="pointer-events-none"
                                // We manually override props to show local state preview
                                taglineClassName="text-gray-500"
                            />
                        </div>
                    </div>
                </CardContent>
            </Card>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {/* Logo Type Selection */}
                <Card>
                    <CardHeader>
                        <CardTitle>Logo Display Mode</CardTitle>
                        <CardDescription>Choose between a text-based or image-based logo.</CardDescription>
                    </CardHeader>
                    <CardContent className="flex gap-4">
                        <Button
                            variant={logo.type === 'text' ? 'default' : 'outline'}
                            onClick={() => setLogo({ ...logo, type: 'text' })}
                            className="flex-1 gap-2"
                        >
                            <Type className="h-4 w-4" /> Text Logo
                        </Button>
                        <Button
                            variant={logo.type === 'image' ? 'default' : 'outline'}
                            onClick={() => setLogo({ ...logo, type: 'image' })}
                            className="flex-1 gap-2"
                        >
                            <ImageIcon className="h-4 w-4" /> Image Logo
                        </Button>
                    </CardContent>
                </Card>

                {/* Icon Management */}
                <Card>
                    <CardHeader>
                        <CardTitle>Blue Logo Icon</CardTitle>
                        <CardDescription>Manage the standalone icon badge.</CardDescription>
                    </CardHeader>
                    <CardContent className="space-y-4">
                        <div className="flex items-center gap-4">
                            <div className="h-12 w-12 rounded border bg-muted flex items-center justify-center overflow-hidden">
                                {icon.type === 'image' && icon.imageUrl ? (
                                    <img src={icon.imageUrl} alt="Icon preview" className="h-full w-full object-contain" />
                                ) : (
                                    <span className="text-primary font-bold">PD</span>
                                )}
                            </div>
                            <div className="flex-1 space-y-1">
                                <p className="text-xs font-medium">Resolution: 128x128px recommended</p>
                                <div className="flex gap-2">
                                    <Button variant="outline" size="sm" asChild className="relative overflow-hidden cursor-pointer h-8 text-xs">
                                        <label>
                                            <Upload className="h-3 w-3 mr-1" /> Replace Icon
                                            <input type="file" className="hidden" accept="image/*" onChange={(e) => handleImageUpload(e, 'icon')} />
                                        </label>
                                    </Button>
                                    {icon.type === 'image' && (
                                        <Button
                                            variant="ghost"
                                            size="sm"
                                            className="h-8 text-xs text-red-600"
                                            onClick={() => setIcon({ type: 'default' })}
                                        >
                                            <Trash2 className="h-3 w-3 mr-1" /> Reset
                                        </Button>
                                    )}
                                </div>
                            </div>
                        </div>
                    </CardContent>
                </Card>
            </div>

            {logo.type === 'text' ? (
                <Card>
                    <CardHeader>
                        <CardTitle>Text Logo Customization</CardTitle>
                        <CardDescription>Style your brand name and tagline.</CardDescription>
                    </CardHeader>
                    <CardContent className="space-y-6">
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            <div className="space-y-2">
                                <label className="text-sm font-medium">Brand Heading</label>
                                <Input
                                    value={logo.text}
                                    onChange={(e) => setLogo({ ...logo, text: e.target.value })}
                                    placeholder="Property Dosti"
                                />
                            </div>
                            <div className="space-y-2">
                                <label className="text-sm font-medium">Tagline</label>
                                <Input
                                    value={logo.tagline}
                                    onChange={(e) => setLogo({ ...logo, tagline: e.target.value })}
                                    placeholder="Broker's virtual Office"
                                />
                            </div>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                            <div className="space-y-2">
                                <label className="text-sm font-medium">Font Size (px)</label>
                                <Input
                                    type="number"
                                    value={logo.fontSize}
                                    onChange={(e) => setLogo({ ...logo, fontSize: parseInt(e.target.value) })}
                                />
                            </div>
                            <div className="space-y-2">
                                <label className="text-sm font-medium">Text Color</label>
                                <div className="flex gap-2">
                                    <Input
                                        type="color"
                                        value={logo.color}
                                        onChange={(e) => setLogo({ ...logo, color: e.target.value })}
                                        className="w-12 p-1 h-10"
                                    />
                                    <Input
                                        value={logo.color}
                                        onChange={(e) => setLogo({ ...logo, color: e.target.value })}
                                        className="flex-1"
                                    />
                                </div>
                            </div>
                        </div>
                    </CardContent>
                </Card>
            ) : (
                <Card>
                    <CardHeader>
                        <CardTitle>Image Logo Upload</CardTitle>
                        <CardDescription>Upload a high-quality version of your logo.</CardDescription>
                    </CardHeader>
                    <CardContent className="space-y-4">
                        <div className="border-2 border-dashed rounded-xl p-12 flex flex-col items-center justify-center transition-colors hover:bg-muted/50 border-muted">
                            {logo.imageUrl ? (
                                <div className="space-y-4 flex flex-col items-center w-full">
                                    <img src={logo.imageUrl} alt="Logo preview" className="max-h-24 max-w-full object-contain" />
                                    <div className="flex gap-2">
                                        <Button variant="outline" size="sm" asChild className="cursor-pointer relative">
                                            <label>
                                                Change Image
                                                <input type="file" className="hidden" accept="image/*" onChange={(e) => handleImageUpload(e, 'logo')} />
                                            </label>
                                        </Button>
                                        <Button variant="ghost" size="sm" className="text-red-600" onClick={() => setLogo({ ...logo, imageUrl: undefined, type: 'text' })}>
                                            <Trash2 className="h-4 w-4 mr-2" /> Remove Image
                                        </Button>
                                    </div>
                                </div>
                            ) : (
                                <div className="text-center space-y-4">
                                    <div className="h-12 w-12 bg-primary/10 rounded-full flex items-center justify-center mx-auto">
                                        <Upload className="h-6 w-6 text-primary" />
                                    </div>
                                    <div className="space-y-1">
                                        <p className="font-medium">Upload Logo Image</p>
                                        <p className="text-xs text-muted-foreground">PNG, SVG or JPG (Max 2MB)</p>
                                        <p className="text-xs text-muted-foreground italic">Recommended dimensions: 300x80px</p>
                                    </div>
                                    <Button variant="default" size="sm" asChild className="cursor-pointer relative">
                                        <label>
                                            Select File
                                            <input type="file" className="hidden" accept="image/*" onChange={(e) => handleImageUpload(e, 'logo')} />
                                        </label>
                                    </Button>
                                </div>
                            )}
                        </div>
                    </CardContent>
                </Card>
            )}

            <div className="flex justify-end pt-4">
                <Button
                    onClick={handleSave}
                    disabled={isLoading}
                    className="w-full md:w-auto px-8 py-6 text-lg shadow-xl shadow-primary/20"
                >
                    {isLoading ? 'Saving...' : 'Save Branding Changes'}
                </Button>
            </div>
        </div>
    );
}

'use client';

import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { cn } from '@/lib/utils';
import { LayoutDashboard, Image as ImageIcon, Settings, Users, Building2, LogOut, X, ChevronLeft } from 'lucide-react';
import { Button } from '@/components/ui/Button';
import { Logo } from '@/components/ui/Logo';

import { useStore } from '@/lib/store';
import { useRouter, useSearchParams } from 'next/navigation';

const sidebarItems = [
    { name: 'Dashboard', href: '/admin', icon: LayoutDashboard },
    { name: 'Banners', href: '/admin/banners', icon: ImageIcon },
    { name: 'Settings', href: '/admin/settings', icon: Settings },
    { name: 'Brokers', href: '/admin?view=brokers', icon: Users },
    { name: 'Properties', href: '/admin?view=properties', icon: Building2 },
];

interface SidebarProps {
    isOpen?: boolean;
    onClose?: () => void;
}

export function Sidebar({ isOpen, onClose }: SidebarProps) {
    const pathname = usePathname();
    const searchParams = useSearchParams();
    const currentView = searchParams.get('view');
    const { logout } = useStore();
    const router = useRouter();

    const handleLogout = () => {
        logout();
        router.push('/login');
    };

    const isActive = (item: any) => {
        if (item.href === '/admin' && !currentView) {
            return pathname === '/admin';
        }
        if (item.href.includes('view=')) {
            return currentView === item.href.split('view=')[1];
        }
        return pathname === item.href;
    };

    return (
        <div className={cn(
            "fixed inset-y-0 left-0 z-[60] w-64 bg-gray-900 text-white transition-transform duration-300 ease-in-out lg:translate-x-0",
            isOpen ? "translate-x-0" : "-translate-x-full"
        )}>
            <div className="flex h-24 items-center justify-center px-4 border-b border-gray-800 bg-gray-900 relative">
                <div className="flex-1 flex items-center justify-center overflow-visible">
                    <Logo
                        iconClassName="text-white"
                        textClassName="text-white"
                        taglineClassName="text-white/70"
                    />
                </div>
            </div>

            {/* Mobile-only Close Arrow: Centered vertically on the right edge to avoid logo conflict */}
            {onClose && (
                <Button
                    variant="ghost"
                    size="icon"
                    onClick={onClose}
                    className="lg:hidden absolute top-1/2 -right-2 transform -translate-y-1/2 bg-primary text-white rounded-full shadow-xl z-50 h-10 w-10 hover:bg-primary/90 border-2 border-gray-900"
                >
                    <ChevronLeft className="h-6 w-6" />
                </Button>
            )}

            <div className="flex-1 py-6 px-3 space-y-1">
                {sidebarItems.map((item) => (
                    <Link
                        key={item.href}
                        href={item.href}
                        onClick={() => onClose?.()}
                        className={cn(
                            "flex items-center px-3 py-3 rounded-lg text-sm font-medium transition-colors hover:bg-gray-800 hover:text-white",
                            isActive(item) ? "bg-gray-800 text-white" : "text-gray-400"
                        )}
                    >
                        <item.icon className="mr-3 h-5 w-5" />
                        {item.name}
                    </Link>
                ))}
            </div>
            <div className="p-4 border-t border-gray-800">
                <Button variant="ghost" className="w-full justify-start text-red-400 hover:text-red-300 hover:bg-red-900/20" onClick={handleLogout}>
                    <LogOut className="mr-3 h-5 w-5" />
                    Logout
                </Button>
            </div>
        </div >
    );
}

'use client';

import { useState, useEffect } from 'react';
import { Check, Search, X } from 'lucide-react';
import { cn } from '@/lib/utils';
import { Badge } from '@/components/ui/Badge';

interface AmenitySelectorProps {
    allAmenities: { name: string; property_types: string[] }[];
    selectedAmenities: string[];
    onToggle: (amenity: string) => void;
    propertyType: string;
}

export function AmenitySelector({
    allAmenities,
    selectedAmenities = [],
    onToggle,
    propertyType
}: AmenitySelectorProps) {
    const [search, setSearch] = useState('');
    const [isOpen, setIsOpen] = useState(false);

    // Filter amenities by property type
    const filteredByPropType = allAmenities.filter(a =>
        a.property_types.includes(propertyType) || a.property_types.length === 0
    );

    const filteredBySearch = filteredByPropType.filter(a =>
        a.name.toLowerCase().includes(search.toLowerCase())
    );

    return (
        <div className="space-y-2">
            <div className="flex flex-wrap gap-1.5 min-h-[32px]">
                {selectedAmenities.length === 0 && (
                    <span className="text-xs text-muted-foreground italic">No amenities selected</span>
                )}
                {selectedAmenities.map(amenity => (
                    <Badge
                        key={amenity}
                        variant="secondary"
                        className="pl-2 pr-1 py-0.5 flex items-center gap-1 bg-primary/10 text-primary border-primary/20"
                    >
                        {amenity}
                        <button
                            type="button"
                            onClick={() => onToggle(amenity)}
                            className="hover:bg-primary/20 rounded-full p-0.5"
                        >
                            <X className="h-3 w-3" />
                        </button>
                    </Badge>
                ))}
            </div>

            <div className="relative">
                <div className="relative">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                    <input
                        type="text"
                        placeholder="Search amenities..."
                        className="flex h-10 w-full rounded-md border border-input bg-background pl-9 pr-3 py-2 text-sm ring-offset-background file:border-0 file:bg-transparent file:text-sm file:font-medium placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2"
                        value={search}
                        onChange={(e) => setSearch(e.target.value)}
                        onFocus={() => setIsOpen(true)}
                    />
                </div>

                {isOpen && (
                    <>
                        <div
                            className="fixed inset-0 z-10"
                            onClick={() => setIsOpen(false)}
                        />
                        <div className="absolute z-20 top-full mt-1 w-full max-h-[200px] overflow-auto rounded-md border bg-popover text-popover-foreground shadow-md animate-in fade-in zoom-in-95">
                            {filteredBySearch.length === 0 ? (
                                <div className="p-3 text-sm text-center text-muted-foreground">No amenities found</div>
                            ) : (
                                <div className="p-1">
                                    {filteredBySearch.map(amenity => {
                                        const isSelected = selectedAmenities.includes(amenity.name);
                                        return (
                                            <button
                                                key={amenity.name}
                                                type="button"
                                                onClick={() => onToggle(amenity.name)}
                                                className={cn(
                                                    "flex items-center justify-between w-full px-3 py-2 text-sm rounded-sm transition-colors",
                                                    isSelected ? "bg-primary/10 text-primary" : "hover:bg-accent hover:text-accent-foreground"
                                                )}
                                            >
                                                {amenity.name}
                                                {isSelected && <Check className="h-4 w-4" />}
                                            </button>
                                        );
                                    })}
                                </div>
                            )}
                        </div>
                    </>
                )}
            </div>
        </div>
    );
}

