'use client';
import { useStore } from '@/lib/store';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/Card';
import { Users, Building2, CheckCircle2, Clock } from 'lucide-react';
import { useState, useEffect } from 'react';
import { BrokerManager } from './BrokerManager';
import { PropertyManager } from './PropertyManager';
import { AmenitiesManager } from './AmenitiesManager';
import { ListChecks } from 'lucide-react';

import { useRouter } from 'next/navigation';

interface AdminDashboardProps {
    view?: 'overview' | 'brokers' | 'properties' | 'amenities';
}

export function AdminDashboard({ view = 'overview' }: AdminDashboardProps) {
    const { brokers, properties } = useStore();
    const [mounted, setMounted] = useState(false);
    const router = useRouter();

    useEffect(() => {
        setMounted(true);
    }, []);

    if (!mounted) return null;

    const pendingBrokers = brokers.filter(b => b.status === 'pending');
    const approvedBrokers = brokers.filter(b => b.status === 'approved');

    const stats = [
        {
            title: "Total Brokers",
            value: brokers.length,
            icon: Users,
            description: "Registered across all districts",
            color: "text-blue-600",
            bgColor: "bg-blue-50",
            targetView: 'brokers'
        },
        {
            title: "Approved Brokers",
            value: approvedBrokers.length,
            icon: CheckCircle2,
            description: "Active members",
            color: "text-green-600",
            bgColor: "bg-green-50",
            targetView: 'brokers'
        },
        {
            title: "Pending Approvals",
            value: pendingBrokers.length,
            icon: Clock,
            description: "Waiting for review",
            color: "text-amber-600",
            bgColor: "bg-amber-50",
            targetView: 'brokers'
        },
        {
            title: "Total Properties",
            value: properties.length,
            icon: Building2,
            description: "Live listings",
            color: "text-purple-600",
            bgColor: "bg-purple-50",
            targetView: 'properties'
        },
        {
            title: "Amenities Config",
            value: "Manage",
            icon: ListChecks,
            description: "Dynamic facility options",
            color: "text-orange-600",
            bgColor: "bg-orange-50",
            targetView: 'amenities'
        }
    ];

    const renderContent = () => {
        switch (view) {
            case 'brokers':
                return <BrokerManager />;
            case 'properties':
                return <PropertyManager />;
            case 'amenities':
                return <AmenitiesManager />;
            default:
                return (
                    <>
                        <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-4">
                            {stats.map((stat) => (
                                <Card
                                    key={stat.title}
                                    className="cursor-pointer transition-all duration-200 hover:shadow-lg hover:-translate-y-1 active:scale-95 group"
                                    onClick={() => router.push(`/admin?view=${stat.targetView}`)}
                                >
                                    <CardHeader className="flex flex-row items-center justify-between pb-2 space-y-0">
                                        <CardTitle className="text-sm font-medium group-hover:text-primary transition-colors">{stat.title}</CardTitle>
                                        <div className={`${stat.bgColor} p-2 rounded-lg group-hover:scale-110 transition-transform`}>
                                            <stat.icon className={`h-4 w-4 ${stat.color}`} />
                                        </div>
                                    </CardHeader>
                                    <CardContent>
                                        <div className="text-2xl font-bold">{stat.value}</div>
                                        <p className="text-xs text-muted-foreground mt-1">{stat.description}</p>
                                    </CardContent>
                                </Card>
                            ))}
                        </div>

                        <div className="mt-12 grid gap-8 md:grid-cols-2">
                            <Card>
                                <CardHeader>
                                    <CardTitle>Recent Activity</CardTitle>
                                </CardHeader>
                                <CardContent>
                                    <p className="text-sm text-muted-foreground">Recent actions will appear here.</p>
                                </CardContent>
                            </Card>
                            <Card>
                                <CardHeader>
                                    <CardTitle>System Health</CardTitle>
                                </CardHeader>
                                <CardContent>
                                    <div className="flex items-center gap-2">
                                        <div className="h-2 w-2 rounded-full bg-green-500"></div>
                                        <span className="text-sm font-medium">Database Connected</span>
                                    </div>
                                    <p className="text-xs text-muted-foreground mt-2">All systems operational.</p>
                                </CardContent>
                            </Card>
                        </div>
                    </>
                );
        }
    };

    return (
        <div className="container py-4 md:py-8 px-2 md:px-4">
            <h1 className="text-3xl font-bold mb-8">
                {view === 'overview' ? 'Admin Overview' :
                    view === 'brokers' ? 'Broker Management' :
                        'Property Management'}
            </h1>

            {renderContent()}
        </div>
    );
}

'use client';

import { useState, useEffect } from 'react';
import { supabase } from '@/lib/supabaseClient';
import { AmenityConfig } from '@/lib/types';
import { Button } from '@/components/ui/Button';
import { Input } from '@/components/ui/Input';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/Card';
import { Plus, Pencil, Trash2, X, Check, Search, Filter } from 'lucide-react';
import { toast } from 'sonner';
import { cn } from '@/lib/utils';

const PROPERTY_TYPES = ['Apartment', 'Villa', 'Farmhouse', 'Land', 'Commercial'];

export function AmenitiesManager() {
    const [amenities, setAmenities] = useState<AmenityConfig[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState('');
    const [filterType, setFilterType] = useState<string>('All');

    // Add/Edit State
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingAmenity, setEditingAmenity] = useState<AmenityConfig | null>(null);
    const [formName, setFormName] = useState('');
    const [formTypes, setFormTypes] = useState<string[]>([]);
    const [isSaving, setIsSaving] = useState(false);

    useEffect(() => {
        fetchAmenities();
    }, []);

    const fetchAmenities = async () => {
        setIsLoading(true);
        const { data, error } = await supabase
            .from('amenities_config')
            .select('*')
            .order('name');

        if (error) {
            toast.error('Failed to fetch amenities');
            console.error(error);
        } else {
            setAmenities(data || []);
        }
        setIsLoading(false);
    };

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!formName.trim()) {
            toast.error('Amenity name is required');
            return;
        }

        setIsSaving(true);
        try {
            if (editingAmenity) {
                const { error } = await supabase
                    .from('amenities_config')
                    .update({
                        name: formName.trim(),
                        property_types: formTypes,
                        updated_at: new Date().toISOString()
                    })
                    .eq('id', editingAmenity.id);

                if (error) throw error;
                toast.success('Amenity updated');
            } else {
                const { error } = await supabase
                    .from('amenities_config')
                    .insert({
                        name: formName.trim(),
                        property_types: formTypes
                    });

                if (error) throw error;
                toast.success('Amenity added');
            }
            setIsModalOpen(false);
            fetchAmenities();
        } catch (error: any) {
            toast.error(error.message || 'Error saving amenity');
        } finally {
            setIsSaving(false);
        }
    };

    const handleDelete = async (id: string) => {
        if (!window.confirm('Are you sure you want to delete this amenity?')) return;

        try {
            const { error } = await supabase
                .from('amenities_config')
                .delete()
                .eq('id', id);

            if (error) throw error;
            toast.success('Amenity deleted');
            fetchAmenities();
        } catch (error: any) {
            toast.error(error.message || 'Error deleting amenity');
        }
    };

    const openModal = (amenity?: AmenityConfig) => {
        if (amenity) {
            setEditingAmenity(amenity);
            setFormName(amenity.name);
            setFormTypes(amenity.property_types);
        } else {
            setEditingAmenity(null);
            setFormName('');
            setFormTypes([]);
        }
        setIsModalOpen(true);
    };

    const toggleType = (type: string) => {
        setFormTypes(prev =>
            prev.includes(type) ? prev.filter(t => t !== type) : [...prev, type]
        );
    };

    const filteredAmenities = amenities.filter(a => {
        const matchesSearch = a.name.toLowerCase().includes(searchQuery.toLowerCase());
        const matchesFilter = filterType === 'All' || a.property_types.includes(filterType);
        return matchesSearch && matchesFilter;
    });

    return (
        <div className="space-y-6">
            <div className="flex flex-col md:flex-row gap-4 items-center justify-between">
                <div className="flex flex-1 gap-2 w-full">
                    <div className="relative flex-1">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                        <Input
                            placeholder="Search amenities..."
                            className="pl-9"
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                        />
                    </div>
                    <select
                        className="h-10 rounded-md border border-input bg-background px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-primary"
                        value={filterType}
                        onChange={(e) => setFilterType(e.target.value)}
                    >
                        <option value="All">All Types</option>
                        {PROPERTY_TYPES.map(t => (
                            <option key={t} value={t}>{t}</option>
                        ))}
                    </select>
                </div>
                <Button onClick={() => openModal()} className="w-full md:w-auto">
                    <Plus className="h-4 w-4 mr-2" /> Add Amenity
                </Button>
            </div>

            <Card>
                <CardHeader className="pb-3 border-b">
                    <CardTitle className="text-lg">Existing Amenities</CardTitle>
                </CardHeader>
                <CardContent className="p-0">
                    <div className="overflow-x-auto">
                        <table className="w-full text-sm text-left">
                            <thead className="bg-muted/50 text-muted-foreground font-medium border-b">
                                <tr>
                                    <th className="px-6 py-3">Amenity Name</th>
                                    <th className="px-6 py-3">Property Types</th>
                                    <th className="px-6 py-3 text-right">Actions</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y">
                                {isLoading ? (
                                    <tr>
                                        <td colSpan={3} className="px-6 py-12 text-center text-muted-foreground">Loading...</td>
                                    </tr>
                                ) : filteredAmenities.length === 0 ? (
                                    <tr>
                                        <td colSpan={3} className="px-6 py-12 text-center text-muted-foreground">No amenities found</td>
                                    </tr>
                                ) : (
                                    filteredAmenities.map((amenity) => (
                                        <tr key={amenity.id} className="hover:bg-muted/30 transition-colors">
                                            <td className="px-6 py-4 font-medium">{amenity.name}</td>
                                            <td className="px-6 py-4">
                                                <div className="flex flex-wrap gap-1">
                                                    {amenity.property_types.map(t => (
                                                        <span key={t} className="px-2 py-0.5 rounded-full bg-primary/10 text-primary text-[10px] font-semibold border border-primary/20">
                                                            {t}
                                                        </span>
                                                    ))}
                                                </div>
                                            </td>
                                            <td className="px-6 py-4 text-right space-x-2">
                                                <Button
                                                    variant="ghost"
                                                    size="icon"
                                                    className="h-8 w-8 text-blue-600 hover:text-blue-700 hover:bg-blue-50"
                                                    onClick={() => openModal(amenity)}
                                                >
                                                    <Pencil className="h-4 w-4" />
                                                </Button>
                                                <Button
                                                    variant="ghost"
                                                    size="icon"
                                                    className="h-8 w-8 text-red-600 hover:text-red-700 hover:bg-red-50"
                                                    onClick={() => handleDelete(amenity.id)}
                                                >
                                                    <Trash2 className="h-4 w-4" />
                                                </Button>
                                            </td>
                                        </tr>
                                    ))
                                )}
                            </tbody>
                        </table>
                    </div>
                </CardContent>
            </Card>

            {/* Modal Dialog for Add/Edit */}
            {isModalOpen && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 animate-in fade-in duration-200">
                    <div className="bg-background rounded-lg shadow-xl w-full max-w-md overflow-hidden animate-in zoom-in-95 duration-200">
                        <div className="flex items-center justify-between p-4 border-b">
                            <h3 className="font-semibold text-lg">{editingAmenity ? 'Edit Amenity' : 'Add New Amenity'}</h3>
                            <button onClick={() => setIsModalOpen(false)} className="text-muted-foreground hover:text-foreground">
                                <X className="h-5 w-5" />
                            </button>
                        </div>
                        <form onSubmit={handleSave} className="p-4 space-y-6">
                            <div className="space-y-2">
                                <label className="text-sm font-medium">Amenity Name</label>
                                <Input
                                    placeholder="e.g. Swimming Pool"
                                    value={formName}
                                    onChange={(e) => setFormName(e.target.value)}
                                    autoFocus
                                />
                            </div>

                            <div className="space-y-3">
                                <label className="text-sm font-medium">Applies to Property Types</label>
                                <div className="grid grid-cols-2 gap-2">
                                    {PROPERTY_TYPES.map(type => {
                                        const isSelected = formTypes.includes(type);
                                        return (
                                            <button
                                                key={type}
                                                type="button"
                                                onClick={() => toggleType(type)}
                                                className={cn(
                                                    "flex items-center justify-between px-3 py-2 text-sm border rounded-md transition-all",
                                                    isSelected
                                                        ? "border-primary bg-primary/5 text-primary ring-1 ring-primary"
                                                        : "border-input bg-background hover:bg-accent"
                                                )}
                                            >
                                                {type}
                                                {isSelected && <Check className="h-4 w-4" />}
                                            </button>
                                        );
                                    })}
                                </div>
                                <p className="text-[10px] text-muted-foreground italic">Select types where this amenity should be available.</p>
                            </div>

                            <div className="pt-4 flex gap-3">
                                <Button
                                    type="button"
                                    variant="outline"
                                    className="flex-1"
                                    onClick={() => setIsModalOpen(false)}
                                >
                                    Cancel
                                </Button>
                                <Button
                                    type="submit"
                                    className="flex-1"
                                    disabled={isSaving}
                                >
                                    {isSaving ? 'Saving...' : 'Save Amenity'}
                                </Button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}

'use client';
import { useStore } from '@/lib/store';
import { Button } from '@/components/ui/Button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/Card';
import { Badge } from '@/components/ui/Badge';
import { Input } from '@/components/ui/Input';
import { Modal } from '@/components/ui/Modal';
import { Check, User, Edit2, Phone, Mail, MapPin, MessageSquare, Trash2 } from 'lucide-react';
import { useState } from 'react';
import { Broker } from '@/lib/types';
import { toast } from 'sonner';
import { supabase } from '@/lib/supabaseClient';
import { sanitizePhone } from '@/lib/utils';

export function BrokerManager() {
    const { brokers, approveBroker, rejectBroker, updateBroker, deleteBroker } = useStore();
    const [editingBroker, setEditingBroker] = useState<Broker | null>(null);

    const pendingBrokers = brokers.filter(b => b.status === 'pending');
    const approvedBrokers = brokers.filter(b => b.status === 'approved');

    const handleApprove = async (id: string, name: string) => {
        try {
            // 1. Fetch broker details for notification and referral check
            const { data: broker, error: fetchError } = await supabase
                .from('profiles')
                .select('phone, unique_broker_id, referred_by, name')
                .eq('id', id)
                .single();

            if (fetchError) throw fetchError;

            // 2. Update status to approved
            const { error: updateError } = await supabase
                .from('profiles')
                .update({ status: 'approved', approval_date: new Date().toISOString() })
                .eq('id', id);

            if (updateError) throw updateError;

            // 3. Handle Referral Reward if applicable
            if (broker.referred_by) {
                // Fetch referrer
                let { data: referrer, error: referrerError } = await supabase
                    .from('profiles')
                    .select('id, subscription_expiry, referral_count, referrals_count, referral_earnings')
                    .eq('id', broker.referred_by)
                    .single();

                // FALLBACK: If referred_by is NOT a UUID (e.g. legacy code), try looking it up by code
                if (referrerError || !referrer) {
                    const { data: fallbackReferrer, error: fallbackError } = await supabase
                        .from('profiles')
                        .select('id, subscription_expiry, referral_count, referrals_count, referral_earnings')
                        .or(`referral_code.eq."${broker.referred_by}",unique_broker_id.eq."${broker.referred_by}"`)
                        .single();

                    if (!fallbackError && fallbackReferrer) {
                        // Update variables for logic below
                        referrer = fallbackReferrer;
                        referrerError = null;
                    }
                }

                if (!referrerError && referrer) {
                    // Extend subscription by 30 days (1 month)
                    const currentExpiry = new Date(referrer.subscription_expiry);
                    const newExpiry = new Date(currentExpiry);
                    newExpiry.setDate(newExpiry.getDate() + 30);

                    await supabase
                        .from('profiles')
                        .update({
                            subscription_expiry: newExpiry.toISOString(),
                            referral_count: (referrer.referral_count || 0) + 1,
                            referrals_count: (referrer.referrals_count || 0) + 1, // update both for safety
                            referral_earnings: (referrer.referral_earnings || 0) + 100
                        })
                        .eq('id', referrer.id);

                    // Track in referrals table
                    await supabase
                        .from('referrals')
                        .insert({
                            referring_broker_id: referrer.id,
                            referred_broker_id: id,
                            referred_person_name: broker.name,
                            referred_contact: broker.phone,
                            admin_approval_status: true,
                            approval_date: new Date().toISOString(),
                            reward_status: 'applied',
                            reward_value: 100
                        });
                }
            }

            // 4. Send WhatsApp Notification
            const { sendWhatsAppNotification } = await import('@/lib/whatsapp');
            await sendWhatsAppNotification(broker.phone, broker.unique_broker_id || 'PD-GENERATING', broker.name);

            // 5. Update local state
            approveBroker(id);
            toast.success(`Approved broker ${name} and notification sent.`);
        } catch (error: any) {
            console.error('Approval error:', error);
            toast.error(`Failed to approve ${name}: ${error.message}`);
        }
    };

    const handleUpdate = async (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault();
        if (!editingBroker) return;

        const { error } = await supabase
            .from('profiles')
            .update({
                name: editingBroker.name,
                phone: editingBroker.phone,
                rera_number: editingBroker.reraNumber,
                city: editingBroker.city,
                village: editingBroker.village,
                company_name: editingBroker.companyName,
                designation: editingBroker.designation,
            })
            .eq('id', editingBroker.id);

        if (error) {
            toast.error(`Failed to update ${editingBroker.name}: ${error.message}`);
        } else {
            updateBroker(editingBroker.id, editingBroker);
            toast.success(`Updated broker ${editingBroker.name}`);
            setEditingBroker(null);
        }
    };

    const handleDelete = async (id: string, name: string) => {
        if (!confirm(`Are you sure you want to permanently delete ${name}? This action cannot be undone.`)) return;

        const { error } = await supabase
            .from('profiles')
            .delete()
            .eq('id', id);

        if (error) {
            console.error("Delete error:", error);
            toast.error(`Failed to delete ${name}: ${error.message || 'Check if you have admin privileges.'}`);
        } else {
            deleteBroker(id);
            toast.success(`Successfully deleted broker ${name}`);
        }
    };

    return (
        <div className="space-y-8">
            <section>
                <h2 className="text-xl font-semibold mb-4">Pending Approvals ({pendingBrokers.length})</h2>
                {pendingBrokers.length === 0 ? (
                    <p className="text-muted-foreground">No pending approvals.</p>
                ) : (
                    <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
                        {pendingBrokers.map((broker) => (
                            <Card key={broker.id}>
                                <CardHeader className="flex flex-row items-center justify-between pb-2">
                                    <div className="flex items-center gap-4">
                                        <div className="h-12 w-12 rounded-full bg-primary/10 flex items-center justify-center">
                                            <User className="h-6 w-6 text-primary" />
                                        </div>
                                        <div>
                                            <CardTitle className="text-lg">{broker.name}</CardTitle>
                                            <CardDescription>{broker.email}</CardDescription>
                                        </div>
                                    </div>
                                    <Button
                                        variant="ghost"
                                        size="sm"
                                        className="h-8 w-8 p-0 text-muted-foreground hover:text-primary"
                                        onClick={() => setEditingBroker(broker)}
                                    >
                                        <Edit2 className="h-4 w-4" />
                                    </Button>
                                </CardHeader>
                                <CardContent>
                                    <div className="space-y-2 text-sm mb-4">
                                        <div className="flex justify-between">
                                            <span className="text-muted-foreground">Phone:</span>
                                            <span>{broker.phone}</span>
                                        </div>
                                        <div className="flex justify-between">
                                            <span className="text-muted-foreground font-bold">Broker ID:</span>
                                            <span className="font-bold text-primary">{broker.uniqueBrokerId || broker.broker_code}</span>
                                        </div>
                                        <div className="flex justify-between">
                                            <span className="text-muted-foreground">RERA:</span>
                                            <span>{broker.reraNumber || 'N/A'}</span>
                                        </div>
                                        {broker.companyName && (
                                            <div className="mt-2 pt-2 border-t text-xs">
                                                <span className="block font-semibold text-gray-700 dark:text-gray-300">{broker.companyName}</span>
                                                {broker.designation && <span className="text-muted-foreground">{broker.designation}</span>}
                                            </div>
                                        )}
                                    </div>
                                    <div className="flex gap-2">
                                        <Button
                                            className="flex-1 bg-green-600 hover:bg-green-700"
                                            size="sm"
                                            onClick={() => handleApprove(broker.id, broker.name)}
                                        >
                                            <Check className="w-4 h-4 mr-1" /> Approve
                                        </Button>
                                        <Button
                                            variant="outline"
                                            className="flex-1 text-red-600 border-red-100 hover:bg-red-50"
                                            size="sm"
                                            onClick={() => handleDelete(broker.id, broker.name)}
                                        >
                                            <Trash2 className="w-4 h-4 mr-1" /> Delete
                                        </Button>
                                    </div>
                                </CardContent>
                            </Card>
                        ))}
                    </div>
                )}
            </section>

            <section>
                <h2 className="text-xl font-semibold mb-4">Approved Brokers ({approvedBrokers.length})</h2>
                {approvedBrokers.length === 0 ? (
                    <div className="p-8 text-center text-muted-foreground border rounded-md bg-white dark:bg-gray-950">No approved brokers yet.</div>
                ) : (
                    <div className="grid gap-4 md:grid-cols-2 xl:grid-cols-3">
                        {approvedBrokers.map((broker) => (
                            <Card key={broker.id} className="overflow-hidden">
                                <CardHeader className="pb-3 bg-green-50/50 dark:bg-green-900/10 border-b">
                                    <div className="flex items-start justify-between gap-2">
                                        <div className="flex items-center gap-3 min-w-0">
                                            <div className="h-10 w-10 rounded-full bg-green-100 dark:bg-green-900/30 flex items-center justify-center shrink-0">
                                                <User className="h-5 w-5 text-green-700 dark:text-green-400" />
                                            </div>
                                            <div className="min-w-0">
                                                <div className="font-bold text-gray-900 dark:text-white truncate">{broker.name}</div>
                                                {broker.companyName && (
                                                    <div className="text-xs text-muted-foreground truncate">{broker.companyName}</div>
                                                )}
                                                <Badge variant="success" className="text-[10px] mt-0.5">Active</Badge>
                                            </div>
                                        </div>
                                        <div className="flex gap-1 shrink-0">
                                            <Button
                                                variant="outline"
                                                size="sm"
                                                className="h-8 w-8 p-0 text-gray-500 border-gray-200 hover:text-primary"
                                                onClick={() => setEditingBroker(broker)}
                                            >
                                                <Edit2 className="h-4 w-4" />
                                            </Button>
                                            <Button
                                                variant="outline"
                                                size="sm"
                                                className="h-8 w-8 p-0 text-green-600 border-green-200"
                                                asChild
                                            >
                                                <a
                                                    href={`https://wa.me/${sanitizePhone(broker.phone)}?text=Hi ${broker.name}, this is Property Dosti Admin. I have a question regarding your account.`}
                                                    target="_blank"
                                                >
                                                    <MessageSquare className="h-4 w-4" />
                                                </a>
                                            </Button>
                                            <Button
                                                variant="outline"
                                                size="sm"
                                                className="h-8 w-8 p-0 text-red-600 border-red-100 hover:bg-red-50"
                                                onClick={() => handleDelete(broker.id, broker.name)}
                                            >
                                                <Trash2 className="h-4 w-4" />
                                            </Button>
                                        </div>
                                    </div>
                                </CardHeader>
                                <CardContent className="pt-4 space-y-3 text-sm">
                                    <div className="flex items-center gap-2 text-muted-foreground">
                                        <Mail className="h-3.5 w-3.5 shrink-0 text-primary" />
                                        <span className="truncate">{broker.email}</span>
                                    </div>
                                    <div className="flex items-center gap-2 text-muted-foreground">
                                        <Phone className="h-3.5 w-3.5 shrink-0 text-primary" />
                                        <span>{broker.phone}</span>
                                    </div>
                                    <div className="flex items-start gap-2 text-muted-foreground">
                                        <MapPin className="h-3.5 w-3.5 shrink-0 text-primary mt-0.5" />
                                        <span>{broker.city || 'N/A'}, {broker.village || 'N/A'}</span>
                                    </div>
                                    <div className="pt-2 border-t">
                                        <div className="flex flex-wrap gap-1 mb-2">
                                            {broker.districts.map(d => (
                                                <Badge key={d} variant="outline" className="text-[10px]">{d}</Badge>
                                            ))}
                                        </div>
                                        <div className="font-mono text-[10px] text-primary bg-primary/5 px-2 py-1 rounded">
                                            Referral Code: {broker.referralCode || 'N/A'}
                                        </div>
                                    </div>
                                </CardContent>
                            </Card>
                        ))}
                    </div>
                )}
            </section>

            {/* Edit Broker Modal */}
            <Modal
                isOpen={!!editingBroker}
                onClose={() => setEditingBroker(null)}
                title="Edit Broker Information"
            >
                {editingBroker && (
                    <form onSubmit={handleUpdate} className="space-y-4">
                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <label className="text-sm font-medium">Name</label>
                                <Input
                                    value={editingBroker.name}
                                    onChange={(e) => setEditingBroker({ ...editingBroker, name: e.target.value })}
                                />
                            </div>
                            <div className="space-y-2">
                                <label className="text-sm font-medium">Email</label>
                                <Input
                                    type="email"
                                    value={editingBroker.email}
                                    onChange={(e) => setEditingBroker({ ...editingBroker, email: e.target.value })}
                                />
                            </div>
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <label className="text-sm font-medium">Company Name</label>
                                <Input
                                    value={editingBroker.companyName || ''}
                                    onChange={(e) => setEditingBroker({ ...editingBroker, companyName: e.target.value })}
                                />
                            </div>
                            <div className="space-y-2">
                                <label className="text-sm font-medium">Designation</label>
                                <Input
                                    value={editingBroker.designation || ''}
                                    onChange={(e) => setEditingBroker({ ...editingBroker, designation: e.target.value })}
                                />
                            </div>
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <label className="text-sm font-medium">Phone</label>
                                <Input
                                    value={editingBroker.phone}
                                    onChange={(e) => setEditingBroker({ ...editingBroker, phone: e.target.value })}
                                />
                            </div>
                            <div className="space-y-2">
                                <label className="text-sm font-medium">RERA Number</label>
                                <Input
                                    value={editingBroker.reraNumber || ''}
                                    onChange={(e) => setEditingBroker({ ...editingBroker, reraNumber: e.target.value })}
                                />
                            </div>
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <label className="text-sm font-medium">City</label>
                                <Input
                                    value={editingBroker.city || ''}
                                    onChange={(e) => setEditingBroker({ ...editingBroker, city: e.target.value })}
                                />
                            </div>
                            <div className="space-y-2">
                                <label className="text-sm font-medium">Local Area/Village</label>
                                <Input
                                    value={editingBroker.village || ''}
                                    onChange={(e) => setEditingBroker({ ...editingBroker, village: e.target.value })}
                                />
                            </div>
                        </div>
                        <div className="pt-4 border-t sticky bottom-0 bg-white dark:bg-gray-900 flex gap-2">
                            <Button type="button" variant="outline" className="flex-1" onClick={() => setEditingBroker(null)}>
                                Cancel
                            </Button>
                            <Button type="submit" className="flex-1">
                                Save Changes
                            </Button>
                        </div>
                    </form>
                )}
            </Modal>
        </div>
    );
}

'use client';
import { useStore } from '@/lib/store';
import { Button } from '@/components/ui/Button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/Card';
import { Badge } from '@/components/ui/Badge';
import { Trash2, ImageIcon } from 'lucide-react';
import { toast } from 'sonner';
import { supabase } from '@/lib/supabaseClient';

export function PropertyManager() {
    const { properties, setProperties } = useStore();

    const handleDeleteProperty = async (id: string, title: string) => {
        if (!confirm(`Are you sure you want to delete property "${title}"?`)) return;

        const { error } = await supabase
            .from('properties')
            .delete()
            .eq('id', id);

        if (error) {
            toast.error(`Failed to delete property: ${error.message}`);
        } else {
            setProperties(properties.filter(p => p.id !== id));
            toast.success(`Deleted property "${title}"`);
        }
    };

    return (
        <section>
            <h2 className="text-xl font-semibold mb-4">Properties Management ({properties.length})</h2>
            <div className="rounded-md border bg-white dark:bg-gray-950 shadow-sm overflow-hidden">
                <div className="hidden md:grid p-4 bg-muted/50 text-xs font-medium grid-cols-5 gap-4 border-b">
                    <div className="col-span-2">Property Details</div>
                    <div>Price</div>
                    <div>Location</div>
                    <div className="text-right">Actions</div>
                </div>
                {properties.length === 0 ? (
                    <div className="p-8 text-center text-muted-foreground">No properties listed yet.</div>
                ) : (
                    properties.map((prop) => (
                        <div key={prop.id} className="p-4 text-sm flex flex-col gap-3 md:grid md:grid-cols-5 md:gap-4 md:items-center border-b last:border-0 hover:bg-muted/20 transition-colors">
                            <div className="md:col-span-2 flex gap-3 items-center w-full">
                                <div className="h-10 w-10 rounded overflow-hidden bg-gray-100 flex-shrink-0 flex items-center justify-center border">
                                    {prop.images && prop.images.length > 0 ? (
                                        <img
                                            src={prop.images[0]}
                                            alt={prop.title}
                                            className="h-full w-full object-cover"
                                            onError={(e) => {
                                                e.currentTarget.style.display = 'none';
                                                e.currentTarget.parentElement?.classList.add('bg-gray-200');
                                            }}
                                        />
                                    ) : (
                                        <ImageIcon className="h-5 w-5 text-gray-400" />
                                    )}
                                </div>
                                <div className="min-w-0 flex-1">
                                    <div className="font-bold text-gray-900 dark:text-white line-clamp-1 break-all">{prop.title}</div>
                                    <div className="text-[10px] text-muted-foreground uppercase tracking-wider">{prop.category} • {prop.type}</div>
                                </div>
                                <div className="md:hidden">
                                    <Button
                                        variant="outline"
                                        size="sm"
                                        className="h-8 w-8 p-0 text-red-600 border-red-100 hover:bg-red-50"
                                        onClick={() => handleDeleteProperty(prop.id, prop.title)}
                                    >
                                        <Trash2 className="h-4 w-4" />
                                    </Button>
                                </div>
                            </div>
                            <div className="flex justify-between md:contents">
                                <div className="flex flex-col md:block">
                                    <span className="md:hidden text-[10px] text-muted-foreground">Price</span>
                                    <span className="font-bold text-primary">₹{prop.price.toLocaleString('en-IN')}</span>
                                </div>
                                <div className="flex flex-col md:block text-right md:text-left">
                                    <span className="md:hidden text-[10px] text-muted-foreground">Location</span>
                                    <span className="text-xs text-muted-foreground block md:truncate">
                                        {prop.location}, {prop.district}
                                    </span>
                                </div>
                            </div>
                            <div className="hidden md:flex text-right justify-end gap-2">
                                <Button
                                    variant="outline"
                                    size="sm"
                                    className="h-8 w-8 p-0 text-red-600 border-red-100 hover:bg-red-50"
                                    onClick={() => handleDeleteProperty(prop.id, prop.title)}
                                >
                                    <Trash2 className="h-4 w-4" />
                                </Button>
                            </div>
                        </div>
                    ))
                )}
            </div>
        </section>
    );
}

'use client';

import { useState } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { supabase } from '@/lib/supabaseClient';
import { Button } from '@/components/ui/Button';
import { Input } from '@/components/ui/Input';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/Card';
import { toast } from 'sonner';
import { Eye, EyeOff, Lock } from 'lucide-react';
import { useRouter } from 'next/navigation';

const changePasswordSchema = z.object({
    password: z.string().min(6, "Password must be at least 6 characters"),
    confirmPassword: z.string(),
}).refine((data) => data.password === data.confirmPassword, {
    message: "Passwords don't match",
    path: ["confirmPassword"],
});

type ChangePasswordFormValues = z.infer<typeof changePasswordSchema>;

export function ChangePasswordForm() {
    const router = useRouter();
    const [isLoading, setIsLoading] = useState(false);
    const [showPassword, setShowPassword] = useState(false);
    const [showConfirmPassword, setShowConfirmPassword] = useState(false);

    const { register, handleSubmit, reset, formState: { errors } } = useForm<ChangePasswordFormValues>({
        resolver: zodResolver(changePasswordSchema)
    });

    const onSubmit = async (data: ChangePasswordFormValues) => {
        setIsLoading(true);
        try {
            const { error } = await supabase.auth.updateUser({
                password: data.password
            });

            if (error) throw error;

            toast.success('Password updated successfully!');
            reset();
            router.push('/'); // Redirect to home or profile
        } catch (error: any) {
            console.error('Error updating password:', error);
            toast.error(error.message || 'Failed to update password');
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <Card className="w-full max-w-md mx-auto shadow-lg">
