                                className="pr-10"
                                placeholder="Min. 6 characters"
                            />
                            <button
                                type="button"
                                onClick={() => setShowPassword(!showPassword)}
                                className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground"
                            >
                                {showPassword ? (
                                    <EyeOff className="h-4 w-4" />
                                ) : (
                                    <Eye className="h-4 w-4" />
                                )}
                            </button>
                        </div>
                        {errors.password && <p className="text-sm text-red-500">{errors.password.message}</p>}
                    </div>

                    <div className="space-y-2">
                        <label htmlFor="confirmPassword">Confirm New Password</label>
                        <div className="relative">
                            <Input
                                id="confirmPassword"
                                type={showConfirmPassword ? "text" : "password"}
                                {...register('confirmPassword')}
                                className="pr-10"
                                placeholder="Re-enter new password"
                            />
                            <button
                                type="button"
                                onClick={() => setShowConfirmPassword(!showConfirmPassword)}
                                className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground"
                            >
                                {showConfirmPassword ? (
                                    <EyeOff className="h-4 w-4" />
                                ) : (
                                    <Eye className="h-4 w-4" />
                                )}
                            </button>
                        </div>
                        {errors.confirmPassword && <p className="text-sm text-red-500">{errors.confirmPassword.message}</p>}
                    </div>

                    <Button type="submit" className="w-full" isLoading={isLoading}>
                        Update Password
                    </Button>
                </form>
            </CardContent>
        </Card>
    );
}

'use client';

import { useState } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { Button } from '@/components/ui/Button';
import { Input } from '@/components/ui/Input';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/Card';
import { toast } from 'sonner';
import Link from 'next/link';
import { Loader2 } from 'lucide-react';
import { supabase } from '@/lib/supabaseClient';

const forgotPasswordSchema = z.object({
    email: z.string().email("Please enter a valid email"),
});

type ForgotPasswordValues = z.infer<typeof forgotPasswordSchema>;

export function ForgotPasswordForm() {
    const [isLoading, setIsLoading] = useState(false);
    const [isSubmitted, setIsSubmitted] = useState(false);

    const { register, handleSubmit, formState: { errors } } = useForm<ForgotPasswordValues>({
        resolver: zodResolver(forgotPasswordSchema),
    });

    const onSubmit = async (data: ForgotPasswordValues) => {
        setIsLoading(true);
        try {
            const { error } = await supabase.auth.resetPasswordForEmail(data.email, {
                redirectTo: `${window.location.origin}/update-password`,
            });

            if (error) {
                // For security, Supabase might always return 200 even if email doesn't exist,
                // but if there's a config error (like SMTP), it will throw here.
                throw error;
            }

            setIsSubmitted(true);
            toast.success('Check your email for reset instructions.');
        } catch (error: any) {
            console.error('Reset password error:', error);
            toast.error(error.message || 'Failed to send reset email.');
        } finally {
            setIsLoading(false);
        }
    };

    if (isSubmitted) {
        return (
            <Card className="w-full max-w-md mx-auto">
                <CardHeader>
                    <CardTitle>Email Sent</CardTitle>
                    <CardDescription>
                        We've sent a password reset link to your email address. Please check your inbox and spam folder.
                    </CardDescription>
                </CardHeader>
                <CardContent className="flex justify-center">
                    <Button asChild variant="outline">
                        <Link href="/login">Return to Login</Link>
                    </Button>
                </CardContent>
            </Card>
        );
    }

    return (
        <Card className="w-full max-w-md mx-auto">
            <CardHeader>
                <CardTitle>Forgot Password</CardTitle>
                <CardDescription>Enter your email to receive recovery instructions</CardDescription>
            </CardHeader>
            <CardContent>
                <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
                    <div className="space-y-2">
                        <label htmlFor="email">Email Address</label>
                        <Input id="email" type="email" {...register('email')} placeholder="name@example.com" />
                        {errors.email && <p className="text-sm text-red-500">{errors.email.message}</p>}
                    </div>
                    <Button type="submit" className="w-full" isLoading={isLoading}>
                        Send Recovery Link
                    </Button>
                    <div className="text-center mt-4">
                        <Link href="/login" className="text-sm text-primary hover:underline">
                            Remember your password? Login
                        </Link>
                    </div>
                </form>
            </CardContent>
        </Card>
    );
}

'use client';

import { useState, useEffect } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { useRouter } from 'next/navigation';
import Link from 'next/link';
import { Button } from '@/components/ui/Button';
import { Input } from '@/components/ui/Input';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/Card';
import { useStore } from '@/lib/store';
import { toast } from 'sonner';
import { supabase } from '@/lib/supabaseClient';

import { Eye, EyeOff } from 'lucide-react';

const loginSchema = z.object({
    email: z.string().email(),
    password: z.string().min(6),
});

type LoginFormValues = z.infer<typeof loginSchema>;

export function LoginForm() {
    const router = useRouter();
    const { brokers, login, user, isAdmin, hasHydrated } = useStore();
    const [isLoading, setIsLoading] = useState(false);
    const [showPassword, setShowPassword] = useState(false);

    useEffect(() => {
        if (hasHydrated && user) {
            if (isAdmin) {
                router.replace('/admin');
            } else {
                router.replace('/dashboard');
            }
        }
    }, [hasHydrated, user, isAdmin, router]);

    const { register, handleSubmit, formState: { errors } } = useForm<LoginFormValues>({
        resolver: zodResolver(loginSchema),
    });

    const onSubmit = async (data: LoginFormValues) => {
        setIsLoading(true);

        try {
            // 1. Sign in with Supabase
            console.log('Attempting login with:', data.email);
            const { data: authData, error: authError } = await supabase.auth.signInWithPassword({
                email: data.email,
                password: data.password,
            });

            if (authError) {
                console.error('Supabase Auth Error:', JSON.stringify(authError, null, 2));
                throw authError; // This might be the empty object source if not serialized
            }
            console.log('Auth successful, User ID:', authData.user?.id);

            if (!authData.user) throw new Error('Login failed: No user data returned');

            // 2. Fetch profile from public.profiles
            const { data: profile, error: profileError } = await supabase
                .from('profiles')
                .select('*')
                .eq('id', authData.user.id)
                .single();

            if (profileError) {
                console.error('Profile Fetch Error:', JSON.stringify(profileError, null, 2));
                if (profileError.code === 'PGRST116') {
                    throw new Error('User profile not found. Please contact the administrator.');
                }
                throw profileError;
            }
            console.log('Profile fetched:', profile);

            // Check if user is admin based on DB flag
            if (profile?.is_admin) {
                // Admin login
                login({ ...profile, isAdmin: true } as any, true);
                toast.success('Welcome Admin');
                router.push('/admin');
                return;
            }

            if (profile.status !== 'approved') {
                toast.error('Your account is pending approval.');
                await supabase.auth.signOut();
                return;
            }

            // 3. Update local store
            const mappedProfile = {
                id: profile.id,
                name: profile.name || 'Unknown',
                email: profile.email || '',
                phone: profile.phone || '',
                broker_code: profile.broker_code || '',
                role: 'broker',
                status: profile.status || 'pending',
                registeredAt: profile.registered_at || new Date().toISOString(),
                subscriptionExpiry: profile.subscription_expiry || new Date().toISOString(),
                referralCode: profile.referral_code || '',
                referredBy: profile.referred_by,
                referralCount: profile.referral_count || 0,
                referralEarnings: profile.referral_earnings || 0,
                uniqueBrokerId: profile.unique_broker_id || `PD-UNASSIGNED-${profile.id.substring(0, 4)}`,
                whatsappNumber: profile.whatsapp_number,
                companyName: profile.company_name,
                designation: profile.designation,
                reraNumber: profile.rera_number,
                districts: profile.districts || [],
                city: profile.city,
                village: profile.village,
                avatarUrl: profile.avatar_url,
            };
            login(mappedProfile as any, false);
            toast.success('Welcome back!');
            router.push('/dashboard');
        } catch (error: any) {
            console.error('Login error:', error);
            toast.error(error.message || 'Invalid credentials');
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <Card className="w-full max-w-md mx-auto">
            <CardHeader>
                <CardTitle>Login</CardTitle>
                <CardDescription>Enter your credentials to access your account</CardDescription>
            </CardHeader>
            <CardContent>
                <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
                    <div className="space-y-2">
                        <label htmlFor="email">Email</label>
                        <Input id="email" type="email" {...register('email')} />
                        {errors.email && <p className="text-sm text-red-500">{errors.email.message}</p>}
                    </div>
                    <div className="space-y-2">
                        <div className="flex items-center justify-between">
                            <label htmlFor="password">Password</label>
                            <Link href="/forgot-password" title="Recover password" className="text-sm text-primary hover:underline">
                                Forgot password?
                            </Link>
                        </div>
                        <div className="relative">
                            <Input
                                id="password"
                                type={showPassword ? "text" : "password"}
                                {...register('password')}
                                className="pr-10"
                            />
                            <button
                                type="button"
                                onClick={() => setShowPassword(!showPassword)}
                                className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground"
                            >
                                {showPassword ? (
                                    <EyeOff className="h-4 w-4" />
                                ) : (
                                    <Eye className="h-4 w-4" />
                                )}
                            </button>
                        </div>
                        {errors.password && <p className="text-sm text-red-500">{errors.password.message}</p>}
                    </div>
                    <Button type="submit" className="w-full" isLoading={isLoading}>
                        Login
                    </Button>
                    <div className="text-center text-sm">
                        Don&apos;t have an account?{" "}
                        <Link href="/signup" className="text-primary hover:underline">
                            Sign up
                        </Link>
                    </div>
                </form>
            </CardContent>
        </Card>
    );
}

'use client';

import { useState } from 'react';
import Link from 'next/link';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { useRouter } from 'next/navigation';
import { Button } from '@/components/ui/Button';
import { Input } from '@/components/ui/Input';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/Card';
import { useStore } from '@/lib/store';
import { DISTRICTS } from '@/lib/types';
import { toast } from 'sonner';
import { supabase } from '@/lib/supabaseClient';
import { useSearchParams } from 'next/navigation';


import { Eye, EyeOff } from 'lucide-react';

const signupSchema = z.object({
    name: z.string().min(2, "Name is required"),
    email: z.string().email(),
    phone: z.string().min(10, "Phone number must be at least 10 digits"),
    companyName: z.string().optional(),
    designation: z.string().optional(),
    password: z.string().min(6, "Password must be at least 6 characters"),
    confirmPassword: z.string(),
    reraNumber: z.string().optional(),
    districts: z.string().min(1, "District selection is mandatory"),
    city: z.string().min(2, "City is required"),
    village: z.string().min(2, "Local Area/Village is required"),
    referralCode: z.string().optional(),
}).refine((data) => data.password === data.confirmPassword, {
    message: "Passwords don't match",
    path: ["confirmPassword"],
});

type SignupFormValues = z.infer<typeof signupSchema>;

export function SignupForm() {
    const router = useRouter();
    const { registerBroker } = useStore();
    const [isLoading, setIsLoading] = useState(false);
    const [showPassword, setShowPassword] = useState(false);
    const [showConfirmPassword, setShowConfirmPassword] = useState(false);

    const searchParams = useSearchParams();
    const brokerIdFromUrl = searchParams.get('broker_id');

    const { register, handleSubmit, formState: { errors } } = useForm<SignupFormValues>({
        resolver: zodResolver(signupSchema) as any,
        defaultValues: {
            districts: "",
            referralCode: brokerIdFromUrl || "",
        }
    });

    const onSubmit = async (data: SignupFormValues) => {
        setIsLoading(true);

        try {
            // 1. Sign up user in Supabase Auth
            const now = new Date();
            const trialExpiry = new Date(now);
            trialExpiry.setDate(trialExpiry.getDate() + 45);
            // broker_code and unique_broker_id are now generated by SQL Trigger
            const myReferralCode = Math.random().toString(36).substring(2, 8).toUpperCase();

            // 1. Sign up user in Supabase Auth (Profile created via Trigger)
            const { data: authData, error: authError } = await supabase.auth.signUp({
                email: data.email,
                password: data.password,
                options: {
                    data: {
                        name: data.name,
                        phone: data.phone,
                        company_name: data.companyName,
                        designation: data.designation,
                        broker_code: null, // Generated by Trigger
                        rera_number: data.reraNumber || null,
                        primary_district: data.districts, // SQL Trigger uses this key
                        city: data.city,
                        village: data.village,
                        registered_at: now.toISOString(),
                        subscription_expiry: trialExpiry.toISOString(),
                        referral_code: myReferralCode,
                        referred_by: data.referralCode || null, // The code they entered
                    }
                }
            });

            if (authError) throw authError;
            if (!authData.user) throw new Error('Signup failed');

            // Note: Manual insert into 'profiles' is removed because the SQL Trigger 'on_auth_user_created' handles it.

            // 3. Handle Referral if applicable
            if (data.referralCode) {
                // We'll need a way to check if referral code is valid in Supabase
                // For now, let's just log it or handle it in a separate function
                console.log('Referral code provided:', data.referralCode);
            }

            // Google Form Integration Logic (Keeping it as requested previously)
            const GOOGLE_FORM_URL = "https://docs.google.com/forms/d/e/1FAIpQLSc62jS8QUvNLoK0knj-THJzLd6zeH6tBcT2VD906FYbtH3Reg/formResponse";
            const formFields = {
                "entry.2005620554": data.name,
                "entry.1045798835": data.email,
                "entry.1168172671": data.phone,
                "entry.1166974658": data.city,
                "entry.839337160": data.village,
            };

            const formData = new FormData();
            Object.entries(formFields).forEach(([key, value]) => {
                formData.append(key, value);
            });

            try {
                await fetch(GOOGLE_FORM_URL, {
                    method: 'POST',
                    mode: 'no-cors',
                    body: formData
                });
            } catch (formError) {
                console.warn('Google Form submission failed:', formError);
                // Do not throw, allow registration to proceed
            }

            toast.success('Registration successful! Please wait for admin approval.');
            router.push('/login');
        } catch (error: any) {
            console.error('Signup error:', error);
            toast.error(error.message || 'Registration failed. Please try again.');
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <Card className="w-full max-w-md mx-auto">
            <CardHeader>
                <CardTitle>Broker Registration</CardTitle>
                <CardDescription>Join our network of verified brokers</CardDescription>
            </CardHeader>
            <CardContent>
                <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
                    <div className="space-y-2">
                        <label htmlFor="name">Name</label>
                        <Input id="name" {...register('name')} />
                        {errors.name && <p className="text-sm text-red-500">{errors.name.message}</p>}
                    </div>

                    <div className="space-y-2">
                        <label htmlFor="email">Email</label>
                        <Input id="email" type="email" {...register('email')} />
                        {errors.email && <p className="text-sm text-red-500">{errors.email.message}</p>}
                    </div>

                    <div className="space-y-2">
                        <label htmlFor="companyName">Company / Agency Name (Optional)</label>
                        <Input id="companyName" {...register('companyName')} placeholder="e.g. Property Dosti Realtors" />
                    </div>

                    <div className="space-y-2">
                        <label htmlFor="designation">Designation (Optional)</label>
                        <Input id="designation" {...register('designation')} placeholder="e.g. Proprietor / Director" />
                    </div>

                    <div className="space-y-2">
                        <label htmlFor="phone">Phone</label>
                        <Input id="phone" {...register('phone')} />
                        {errors.phone && <p className="text-sm text-red-500">{errors.phone.message}</p>}
                    </div>

                    <div className="space-y-2">
                        <label htmlFor="password">Password</label>
                        <div className="relative">
                            <Input
                                id="password"
                                type={showPassword ? "text" : "password"}
                                {...register('password')}
                                className="pr-10"
                            />
                            <button
                                type="button"
                                onClick={() => setShowPassword(!showPassword)}
                                className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground"
                            >
                                {showPassword ? (
                                    <EyeOff className="h-4 w-4" />
                                ) : (
                                    <Eye className="h-4 w-4" />
                                )}
                            </button>
                        </div>
                        {errors.password && <p className="text-sm text-red-500">{errors.password.message}</p>}
                    </div>

                    <div className="space-y-2">
                        <label htmlFor="confirmPassword">Confirm Password</label>
                        <div className="relative">
                            <Input
                                id="confirmPassword"
                                type={showConfirmPassword ? "text" : "password"}
                                {...register('confirmPassword')}
                                className="pr-10"
                            />
                            <button
                                type="button"
                                onClick={() => setShowConfirmPassword(!showConfirmPassword)}
                                className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground"
                            >
                                {showConfirmPassword ? (
                                    <EyeOff className="h-4 w-4" />
                                ) : (
                                    <Eye className="h-4 w-4" />
                                )}
                            </button>
                        </div>
                        {errors.confirmPassword && <p className="text-sm text-red-500">{errors.confirmPassword.message}</p>}
                    </div>

                    <div className="space-y-2">
                        <label htmlFor="reraNumber">RERA Number (Optional)</label>
                        <Input id="reraNumber" {...register('reraNumber')} />
                    </div>

                    <div className="space-y-2">
                        <label htmlFor="district" className="block text-sm font-medium">Primary District</label>
                        <select
                            id="district"
                            {...register('districts')}
                            className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm ring-offset-background file:border-0 file:bg-transparent file:text-sm file:font-medium placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:cursor-not-allowed disabled:opacity-50"
                        >
                            <option value="">Select a District</option>
                            {DISTRICTS.map((district) => (
                                <option key={district} value={district}>
                                    {district}
                                </option>
                            ))}
                        </select>
                        {errors.districts && <p className="text-sm text-red-500">{errors.districts.message}</p>}
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-2">
                            <label htmlFor="city">City</label>
                            <Input id="city" {...register('city')} placeholder="City" />
                            {errors.city && <p className="text-sm text-red-500">{errors.city.message}</p>}
                        </div>
                        <div className="space-y-2">
                            <label htmlFor="village">Local Area/Village</label>
                            <Input id="village" {...register('village')} placeholder="Local Area/Village" />
                            {errors.village && <p className="text-sm text-red-500">{errors.village.message}</p>}
                        </div>
                    </div>

                    <div className="space-y-2">
                        <label htmlFor="referralCode">Referral Code {brokerIdFromUrl ? "(Applied)" : "(Optional)"}</label>
                        <Input
                            id="referralCode"
                            {...register('referralCode')}
                            placeholder="Enter code for bonus"
                            readOnly={!!brokerIdFromUrl}
                            className={brokerIdFromUrl ? "bg-gray-100 cursor-not-allowed font-bold text-primary" : ""}
                        />
                    </div>

                    <div className="space-y-4 pt-4 border-t border-gray-100">
                        <p className="text-sm font-bold text-gray-900 dark:text-white mb-2">Legal Agreements</p>

                        <div className="flex items-start gap-3">
                            <input
                                type="checkbox"
                                id="legalAgreement"
                                required
                                className="mt-1 h-4 w-4 rounded border-gray-300 text-primary focus:ring-primary"
                            />
                            <label htmlFor="legalAgreement" className="text-sm text-muted-foreground leading-tight">
                                I agree to the <Link href="/terms" target="_blank" className="text-primary hover:underline font-semibold">Terms of Service</Link>, <Link href="/privacy" target="_blank" className="text-primary hover:underline font-semibold">Privacy Policy</Link>, and <Link href="/refund" target="_blank" className="text-primary hover:underline font-semibold">Refund & Cancellation Policy</Link>.
                            </label>
                        </div>
                    </div>

                    <Button type="submit" className="w-full h-12 text-lg font-black tracking-tight" isLoading={isLoading}>
                        Register
                    </Button>
                </form>
            </CardContent>
        </Card>
    );
}

'use client';

import { useState, useEffect } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { Button } from '@/components/ui/Button';
import { Input } from '@/components/ui/Input';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/Card';
import { toast } from 'sonner';
import { useRouter } from 'next/navigation';
import { supabase } from '@/lib/supabaseClient';
import { Eye, EyeOff } from 'lucide-react';

const updatePasswordSchema = z.object({
    password: z.string().min(6, "Password must be at least 6 characters"),
    confirmPassword: z.string(),
}).refine((data) => data.password === data.confirmPassword, {
    message: "Passwords don't match",
    path: ["confirmPassword"],
});

type UpdatePasswordValues = z.infer<typeof updatePasswordSchema>;

export function UpdatePasswordForm() {
    const router = useRouter();
    const [isLoading, setIsLoading] = useState(false);
    const [showPassword, setShowPassword] = useState(false);

    const { register, handleSubmit, formState: { errors } } = useForm<UpdatePasswordValues>({
        resolver: zodResolver(updatePasswordSchema),
    });

    useEffect(() => {
        // Check if we have a session (user clicked email link)
        supabase.auth.getSession().then(({ data: { session } }) => {
            if (!session) {
                toast.error('Invalid or expired reset link.');
                router.push('/login');
            }
        });
    }, [router]);

    const onSubmit = async (data: UpdatePasswordValues) => {
        setIsLoading(true);
        try {
            const { error } = await supabase.auth.updateUser({
                password: data.password
            });

            if (error) throw error;

            toast.success('Password updated successfully!');
            router.push('/login');
        } catch (error: any) {
            console.error('Update password error:', error);
            toast.error(error.message || 'Failed to update password.');
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <Card className="w-full max-w-md mx-auto">
            <CardHeader>
                <CardTitle>Set New Password</CardTitle>
                <CardDescription>Enter your new password below</CardDescription>
            </CardHeader>
            <CardContent>
                <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
                    <div className="space-y-2">
                        <label htmlFor="password">New Password</label>
                        <div className="relative">
                            <Input
                                id="password"
                                type={showPassword ? "text" : "password"}
                                {...register('password')}
                                className="pr-10"
                            />
                            <button
                                type="button"
                                onClick={() => setShowPassword(!showPassword)}
                                className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground"
                            >
                                {showPassword ? (
                                    <EyeOff className="h-4 w-4" />
                                ) : (
                                    <Eye className="h-4 w-4" />
                                )}
                            </button>
                        </div>
                        {errors.password && <p className="text-sm text-red-500">{errors.password.message}</p>}
                    </div>

                    <div className="space-y-2">
                        <label htmlFor="confirmPassword">Confirm Password</label>
                        <Input id="confirmPassword" type="password" {...register('confirmPassword')} />
                        {errors.confirmPassword && <p className="text-sm text-red-500">{errors.confirmPassword.message}</p>}
                    </div>

                    <Button type="submit" className="w-full" isLoading={isLoading}>
                        Update Password
                    </Button>
                </form>
            </CardContent>
        </Card>
    );
}

'use client'; // Broker Dashboard Features
import { useState, useEffect, useCallback } from 'react';
import { useStore } from '@/lib/store';
import { Property, DISTRICTS } from '@/lib/types';
import { Button } from '@/components/ui/Button';
import { PropertyCard } from '@/components/PropertyCard';
import { cn } from '@/lib/utils';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/Card';
import { Badge } from '@/components/ui/Badge';
import { Plus, Search, MapPin, Clock, MessageSquare, Pencil, Trash2, Camera, Check, Share2, User as UserIcon, MoreVertical, Eye, Gift } from 'lucide-react';
import { DropdownMenu, DropdownMenuItem } from '@/components/ui/DropdownMenu';
import { Input } from '@/components/ui/Input';
import { Modal } from '@/components/ui/Modal';
import { SubscriptionDashboard } from '@/features/subscription/SubscriptionDashboard';
import { SmartSearchForm, SmartSearchFilters } from '@/components/SmartSearchForm';
import { ReferralBanner } from '@/components/broker/ReferralBanner';
import { AmenitySelector } from '@/components/broker/AmenitySelector';
import { supabase } from '@/lib/supabaseClient';
import { useSearchParams, useRouter } from 'next/navigation';

import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { toast } from 'sonner';

const propertySchema = z.object({
    title: z.string().min(3, "Title must be at least 3 characters"),
    description: z.string().min(10, "Description must be at least 10 characters"),
    price: z.coerce.number().min(1, "Price is required"),
    district: z.string().min(1, "District is mandatory"),
    location: z.string().min(2, "Village/City/Area is required"),
    type: z.enum(['sale', 'rent', 'lease']),
    category: z.string().optional().nullable().or(z.literal('')),
    structureType: z.string().optional().nullable().or(z.literal('')),
    landArea: z.coerce.number().optional().nullable(),
    floorNumber: z.coerce.number().optional().nullable(),
    floorDetail: z.string().optional().nullable(),
    parkingSpaces: z.coerce.number().optional().nullable(),
    parkingType: z.string().optional().nullable().or(z.literal('')),
    parkingAllocated: z.string().optional().nullable(),
    facilities: z.array(z.string()).optional().nullable(),
    googleMapLink: z.string().optional().nullable().or(z.literal('')),
    village: z.string().optional().nullable(),
    hidePrice: z.boolean().optional(),
});

type PropertyFormValues = z.infer<typeof propertySchema>;

export function BrokerDashboard() {
    const { user, properties, addProperty, setProperties, updateProperty, deleteProperty, setUser } = useStore();
    const searchParams = useSearchParams();
    const router = useRouter();
    const viewParam = searchParams.get('view');

    const [isAddModalOpen, setIsAddModalOpen] = useState(false);
    const [isEditModalOpen, setIsEditModalOpen] = useState(false);
    const [selectedProperty, setSelectedProperty] = useState<Property | null>(null);
    const [isDeleting, setIsDeleting] = useState<string | null>(null);
    const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
    const [propertyToDelete, setPropertyToDelete] = useState<string | null>(null);
    const editParam = searchParams.get('edit');

    const [searchFilters, setSearchFilters] = useState<SmartSearchFilters>({
        searchBy: 'city',
        query: '',
        propertyType: ''
    });
    const [uploadedImages, setUploadedImages] = useState<string[]>([]);
    const [activeTab, setActiveTab] = useState<'explore' | 'listings' | 'responses' | 'subscription' | 'profile'>('explore');
    const [isLoading, setIsLoading] = useState(false);
    const [isUploadingAvatar, setIsUploadingAvatar] = useState(false);
    const [listingSearch, setListingSearch] = useState('');
    const [amenitiesConfig, setAmenitiesConfig] = useState<any[]>([]);
    const [referralStats, setReferralStats] = useState<any[]>([]);

    // Form Watch for Conditional Logic
    const { register, handleSubmit, reset, watch, formState: { errors }, setValue } = useForm<PropertyFormValues>({
        resolver: zodResolver(propertySchema) as any,
        defaultValues: {
            district: '',
            structureType: 'Villa',
            type: 'sale',
            category: 'residential'
        }
    });

    const structureType = watch('structureType');
    const parkingSpaces = watch('parkingSpaces');
    const priceValue = watch('price');

    const broker = user && 'subscriptionExpiry' in user ? user : null;
    const isSubscriptionExpired = broker ? new Date(broker.subscriptionExpiry) < new Date() : false;

    const myProperties = properties.filter(p => p.brokerId === user?.id);
    const filteredMyProperties = myProperties.filter(p =>
        p.title.toLowerCase().includes(listingSearch.toLowerCase()) ||
        p.location.toLowerCase().includes(listingSearch.toLowerCase()) ||
        p.district.toLowerCase().includes(listingSearch.toLowerCase())
    );
    const [propertyLeads, setPropertyLeads] = useState<any[]>([]); // Local state for leads
    const myLeads = propertyLeads;
    const unreadCount = myLeads.filter(l => l.status === 'new').length;

    // Fetch properties from Supabase
    useEffect(() => {
        const fetchProperties = async () => {
            const { data, error } = await supabase
                .from('properties')
                .select(`
                    *,
                    profiles (
                        phone
                    )
                `)
                .order('created_at', { ascending: false });

            if (error) {
                console.error('Error fetching properties:', error);
            } else if (data) {
                const mappedProperties: Property[] = data.map((p: any) => ({
                    id: p.id,
                    brokerId: p.broker_id,
                    title: p.title,
                    description: p.description,
                    price: p.price,
                    district: p.district,
                    location: p.location,
                    type: p.type,
                    category: p.category,
                    structureType: p.structure_type,
                    landArea: p.land_area,
                    floorNumber: p.floor_number,
                    floorDetail: p.floor_detail,
                    parkingSpaces: p.parking_spaces,
                    parkingType: p.parking_type,
                    parkingAllocated: p.parking_allocated,
                    facilities: p.facilities,
                    googleMapLink: p.google_map_link,
                    images: p.images,
                    village: p.village,
                    createdAt: p.created_at,
                    updatedAt: p.updated_at,
                    expiresAt: p.expires_at,
                    isActive: p.is_active,
                    likes: p.likes,
                    leadsCount: p.leads_count,
                    amenities: p.amenities,
                    brokerPhone: p.profiles?.phone,
                }));
                setProperties(mappedProperties);
            }
        };

        fetchProperties();
    }, [setProperties]);

    // Fetch leads for the current broker
    useEffect(() => {
        const fetchLeads = async () => {
            if (!user) return;
            const { data, error } = await supabase
                .from('property_leads')
                .select('*')
                .eq('broker_id', user.id)
                .order('timestamp', { ascending: false });

            if (error) {
                console.error('Error fetching leads:', error);
            } else if (data) {
                setPropertyLeads(data);
            }
        };

        fetchLeads();
    }, [user]);

    useEffect(() => {
        const fetchReferrals = async () => {
            if (!user) return;
            const { data, error } = await supabase
                .from('referrals')
                .select('*')
                .eq('referring_broker_id', user.id)
                .order('created_at', { ascending: false });

            if (error) {
                console.error('Error fetching referrals:', error.message || error, error.details, error.hint);
            } else if (data) {
                setReferralStats(data);
            }
        };
        fetchReferrals();
    }, [user]);

    // Fetch amenities config
    useEffect(() => {
        const fetchAmenities = async () => {
            const { data, error } = await supabase
                .from('amenities_config')
                .select('*')
                .order('name');
            if (error) {
                console.error('Error fetching amenities:', error);
            } else if (data) {
                setAmenitiesConfig(data);
            }
        };
        fetchAmenities();
    }, []);

    const markLeadAsRead = async (leadId: string) => {
        // Optimistic update
        setPropertyLeads(prev => prev.map(l => l.id === leadId ? { ...l, status: 'read' } : l));

        const { error } = await supabase
            .from('property_leads')
            .update({ status: 'read' })
            .eq('id', leadId);

        if (error) {
            console.error('Error marking lead strictly as read:', error);
        }
    };

    const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const files = Array.from(e.target.files || []);
        if (files.length + uploadedImages.length > 3) {
            toast.error('You can only upload up to 3 images.');
            return;
        }

        setIsLoading(true);
        const newImageUrls: string[] = [];

        for (const file of files) {
            if (file.size > 1024 * 1024) { // 1MB limit for Supabase
                toast.error(`${file.name} is too large. Please use images < 1MB.`);
                continue;
            }

            try {
                const fileExt = file.name.split('.').pop();
                const fileName = `${Math.random().toString(36).substring(2)}.${fileExt}`;
                const filePath = `${user?.id}/${fileName}`;

                const { error: uploadError } = await supabase.storage
                    .from('property-images')
                    .upload(filePath, file);

                if (uploadError) throw uploadError;

                const { data: { publicUrl } } = supabase.storage
                    .from('property-images')
                    .getPublicUrl(filePath);

                newImageUrls.push(publicUrl);
            } catch (error: any) {
                console.error('Error uploading image:', error);
                toast.error(`Failed to upload ${file.name}`);
            }
        }

        setUploadedImages(prev => [...prev, ...newImageUrls]);
        setIsLoading(false);
    };

    const onSubmit = async (data: PropertyFormValues) => {
        if (!user) return;
        setIsLoading(true);

        // Process facilities: already an array from Zod
        const facilitiesArray = data.facilities || [];

        // Determine category based on structure type if needed
        let finalCategory = data.category;
        if (data.structureType === 'Land' && data.category) {
            // Keep user selection for Land
        } else {
            // Default mapping
            if (['Villa', 'Apartment', 'Farmhouse'].includes(data.structureType || '')) {
                finalCategory = 'residential';
            }
        }

        try {
            const { data: propertyData, error: propertyError } = await supabase
                .from('properties')
                .insert({
                    broker_id: user.id,
                    title: data.title,
                    description: data.description,
                    price: data.price,
                    district: data.district,
                    location: data.location,
                    type: data.type,
                    category: finalCategory,
                    structure_type: data.structureType,
                    land_area: data.landArea || null,
                    floor_number: data.floorNumber || null,
                    floor_detail: data.floorDetail,
                    parking_spaces: data.parkingSpaces || 0,
                    parking_type: data.parkingType,
                    parking_allocated: data.parkingAllocated,
                    facilities: facilitiesArray,
                    google_map_link: data.googleMapLink,
                    hide_price: data.hidePrice || false,
                    images: uploadedImages,
                    amenities: [], // Can extended similarly later
                })
                .select()
                .single();

            if (propertyError) throw propertyError;

            // Update local state by adding the new property at the top
            const p = propertyData;
            const newProperty: Property = {
                id: p.id,
                brokerId: p.broker_id,
                title: p.title,
                description: p.description,
                price: p.price,
                district: p.district,
                location: p.location,
                type: p.type,
                category: p.category,
                structureType: p.structure_type,
                landArea: p.land_area,
                floorNumber: p.floor_number,
                floorDetail: p.floor_detail,
                parkingSpaces: p.parking_spaces,
                parkingType: p.parking_type,
                parkingAllocated: p.parking_allocated,
                facilities: p.facilities,
                googleMapLink: p.google_map_link,
                hidePrice: p.hide_price,
                images: p.images,
                createdAt: p.created_at,
                updatedAt: p.updated_at,
                expiresAt: p.expires_at,
                isActive: p.is_active,
                likes: p.likes,
                leadsCount: p.leads_count,
                amenities: p.amenities,
            };

            addProperty(newProperty);
            toast.success('Property listed successfully!');
            setIsAddModalOpen(false);
            setUploadedImages([]);
            reset();
        } catch (error: any) {
            console.error('Error adding property:', error);
            toast.error(error.message || 'Failed to list property.');
        } finally {
            setIsLoading(false);
        }
    };

    const filteredProperties = properties.filter(p => {
        const matchesQuery = !searchFilters.query || (
            searchFilters.searchBy === 'city' ? (p.location.toLowerCase().includes(searchFilters.query.toLowerCase()) || p.village?.toLowerCase().includes(searchFilters.query.toLowerCase())) :
                searchFilters.searchBy === 'district' ? p.district.toLowerCase().includes(searchFilters.query.toLowerCase()) :
                    searchFilters.searchBy === 'village' ? (p.village?.toLowerCase().includes(searchFilters.query.toLowerCase()) || p.location.toLowerCase().includes(searchFilters.query.toLowerCase())) :
                        p.profiles?.name?.toLowerCase().includes(searchFilters.query.toLowerCase())
        );

        const matchesType = !searchFilters.propertyType || (
            p.category.toLowerCase() === searchFilters.propertyType.toLowerCase() ||
            p.structureType?.toLowerCase() === searchFilters.propertyType.toLowerCase()
        );

        return matchesQuery && matchesType;
    });

    const handleEdit = useCallback((property: Property) => {
        setSelectedProperty(property);
        setUploadedImages(property.images || []);

        // Populate form
        setValue('title', property.title);
        setValue('description', property.description);
        setValue('price', property.price);
        setValue('district', property.district);
        setValue('location', property.location);
        setValue('type', property.type);
        setValue('category', property.category as any);
        setValue('structureType', (property.structureType as any) || 'Villa');
        setValue('landArea', property.landArea);
        setValue('floorNumber', property.floorNumber);
        setValue('floorDetail', property.floorDetail);
        setValue('parkingSpaces', property.parkingSpaces);
        setValue('parkingType', property.parkingType as any);
        setValue('parkingAllocated', property.parkingAllocated);
        setValue('facilities', property.facilities || []);
        setValue('googleMapLink', property.googleMapLink || '');
        setValue('village', property.village || '');

        setIsEditModalOpen(true);
    }, [setValue]);

    // Sync active tab with URL search param
    useEffect(() => {
        if (viewParam) {
            setActiveTab(viewParam as any);
        } else {
            setActiveTab('explore');
        }

        // Handle direct edit link
        if (editParam && properties.length > 0) {
            const propertyToEdit = properties.find(p => p.id === editParam);
            if (propertyToEdit && propertyToEdit.brokerId === user?.id) {
                handleEdit(propertyToEdit);
                // Clear the param from URL to avoid reopening on refresh
                const newParams = new URLSearchParams(searchParams.toString());
                newParams.delete('edit');
                router.replace(`/dashboard?${newParams.toString()}`);
            }
        }
    }, [viewParam, editParam, properties, user, handleEdit, router, searchParams]);

    const handleDelete = async (id: string) => {
        setIsDeleting(id);
        try {
            const { error } = await supabase
                .from('properties')
                .delete()
                .eq('id', id);

            if (error) throw error;

            deleteProperty(id);
            toast.success('Property deleted successfully');
            setIsDeleteModalOpen(false);
        } catch (error: any) {
            toast.error(error.message || 'Failed to delete property');
        } finally {
            setIsDeleting(null);
        }
    };

    const onAvatarUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file || !user) return;

        if (file.size > 500 * 1024) {
            toast.error('Avatar image must be less than 500KB');
            return;
        }

        setIsUploadingAvatar(true);
        try {
            const fileExt = file.name.split('.').pop();
            const fileName = `avatar_${user.id}_${Date.now()}.${fileExt}`;
            const filePath = `avatars/${fileName}`;

            const { error: uploadError } = await supabase.storage
                .from('property-images')
                .upload(filePath, file);

            if (uploadError) throw uploadError;

            const { data: { publicUrl } } = supabase.storage
                .from('property-images')
                .getPublicUrl(filePath);

            const { error: updateError } = await supabase
                .from('profiles')
                .update({ avatar_url: publicUrl })
                .eq('id', user.id);

            if (updateError) throw updateError;

            // Update local user state
            setUser({ ...user, avatarUrl: publicUrl } as any);
            toast.success('Profile picture updated!');
        } catch (error: any) {
            console.error('Error uploading avatar:', error);
            toast.error('Failed to upload profile picture');
        } finally {
            setIsUploadingAvatar(false);
        }
    };

    const [mounted, setMounted] = useState(false);
    useEffect(() => {
        setMounted(true);
    }, []);

    if (!mounted) return null;

    return (
        <div className="bg-transparent pb-10">
            <div className="px-0">
                {/* Header Section */}
                <div className="flex flex-col md:flex-row items-center justify-between gap-4 mb-8">
                    <div>
                        <h1 className="text-3xl font-bold tracking-tight">
                            {activeTab === 'explore' && 'Global Properties'}
                            {activeTab === 'listings' && 'My Property Listings'}
                            {activeTab === 'responses' && 'Customer Responses'}
                            {activeTab === 'subscription' && 'Membership & Rewards'}
                            {activeTab === 'profile' && 'My Profile'}
                        </h1>
                        <p className="text-muted-foreground">
                            {activeTab === 'explore' && 'Explore verified properties across the network.'}
                            {activeTab === 'listings' && 'Manage and monitor your property listings.'}
                            {activeTab === 'responses' && 'View and manage inquiries from interested buyers.'}
                            {activeTab === 'subscription' && 'Upgrade your account for premium features.'}
                            {activeTab === 'profile' && 'View and update your professional profile.'}
                        </p>
                    </div>
                    {activeTab === 'listings' && (
                        <Button
                            onClick={() => {
                                if (isSubscriptionExpired) {
                                    toast.error('Subscription expired! Please renew to add new properties.');
                                } else {
                                    setIsAddModalOpen(true);
                                    reset();
                                    setUploadedImages([]);
                                }
                            }}
                            className="shadow-lg shadow-primary/20"
                            variant={(isSubscriptionExpired ? "outline" : "default") as any}
                        >
                            <Plus className="mr-2 h-4 w-4" /> Add Property
                        </Button>
                    )}
                </div>

                {activeTab === 'explore' && (
                    <>
                        {/* Membership & Rewards Section - Only on Explore/Dashboard home */}
                        <div className="mb-12">
                            <h2 className="text-xl font-bold mb-6 flex items-center gap-2">
                                <Badge variant="outline" className="text-primary border-primary">NEW</Badge>
                                Membership Upgrade
                            </h2>
                            <SubscriptionDashboard />
                        </div>

                        {broker?.uniqueBrokerId && (
                            <div className="mb-12">
                                <ReferralBanner
                                    referralCode={broker.referralCode}
                                    uniqueBrokerId={broker.uniqueBrokerId}
                                />
                            </div>
                        )}

                        <div className="mb-10">
                            <SmartSearchForm
                                onSearch={(f) => setSearchFilters(f)}
                                initialFilters={searchFilters}
                                className="shadow-sm border border-gray-100 bg-white"
                            />
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                            {filteredProperties.map((property) => (
                                <div key={property.id} className="h-full">
                                    <PropertyCard property={property} />
                                </div>
                            ))}
                        </div>
                    </>
                )}

                {activeTab === 'listings' && (
                    <div className="space-y-6">
                        {/* Compact Search Bar */}
                        <div className="relative max-w-md">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                            <Input
                                placeholder="Quick search by title or location..."
                                className="pl-10 h-10 border-gray-200 focus:ring-primary/20"
                                value={listingSearch}
                                onChange={(e) => setListingSearch(e.target.value)}
                            />
                        </div>

                        <div className="grid gap-4">
                            {myProperties.length === 0 ? (
                                <Card className="p-12 text-center">
                                    <p className="text-muted-foreground">You haven&apos;t listed any properties yet.</p>
                                    <Button
                                        variant={"outline" as any}
                                        className="mt-4"
                                        onClick={() => setIsAddModalOpen(true)}
                                    >
                                        Create Your First Listing
                                    </Button>
                                </Card>
                            ) : filteredMyProperties.length === 0 ? (
                                <div className="p-12 text-center text-muted-foreground bg-muted/20 rounded-lg border border-dashed">
                                    No properties match your search.
                                </div>
                            ) : (
                                <div className="grid grid-cols-1 gap-4">
                                    {filteredMyProperties.map((p) => (
                                        <Card key={p.id} className="overflow-hidden hover:shadow-sm transition-shadow border-gray-100 dark:border-gray-800 relative">
                                            <div className="absolute top-2 right-2 z-10">
                                                <DropdownMenu
                                                    trigger={
                                                        <Button variant="ghost" size="sm" className="h-8 w-8 p-0 rounded-full bg-white/80 backdrop-blur hover:bg-white shadow-sm border border-gray-100">
                                                            <MoreVertical className="h-4 w-4 text-gray-600" />
                                                        </Button>
                                                    }
                                                >
                                                    <DropdownMenuItem onClick={() => window.open(`/property/${p.id}`, '_blank')}>
                                                        <Eye className="h-4 w-4" /> View
                                                    </DropdownMenuItem>
                                                    <DropdownMenuItem onClick={() => handleEdit(p)}>
                                                        <Pencil className="h-4 w-4" /> Edit
                                                    </DropdownMenuItem>
                                                    <DropdownMenuItem
                                                        variant="danger"
                                                        onClick={() => {
                                                            setPropertyToDelete(p.id);
                                                            setIsDeleteModalOpen(true);
                                                        }}
                                                    >
                                                        <Trash2 className="h-4 w-4" /> Delete
                                                    </DropdownMenuItem>
                                                </DropdownMenu>
                                            </div>
                                            <CardContent className="p-3 sm:p-4">
                                                <div className="flex gap-4">
                                                    {/* Left Column: Image */}
                                                    <div className="flex flex-col gap-2 w-24 sm:w-32 flex-shrink-0">
                                                        <div className="relative aspect-square rounded-lg overflow-hidden bg-muted">
                                                            {p.images && p.images.length > 0 ? (
                                                                <img
                                                                    src={p.images[0]}
                                                                    alt={p.title}
                                                                    className="w-full h-full object-cover"
                                                                />
                                                            ) : (
                                                                <div className="w-full h-full flex items-center justify-center">
                                                                    <Camera className="h-6 w-6 text-muted-foreground/30" />
                                                                </div>
                                                            )}
                                                            <div className="absolute top-1 left-1">
                                                                <Badge
                                                                    className={cn(
                                                                        "px-1.5 py-0 text-[10px] uppercase font-bold",
                                                                        p.isActive ? "bg-green-500" : "bg-gray-400"
                                                                    )}
                                                                >
                                                                    {p.isActive ? "Live" : "Draft"}
                                                                </Badge>
                                                            </div>
                                                        </div>
                                                    </div>

                                                    {/* Right Column: Details */}
                                                    <div className="flex-1 flex flex-col justify-between py-1">
                                                        <div className="space-y-1.5">
                                                            <div className="space-y-0.5">
                                                                <h3 className="text-xl font-bold text-gray-900 dark:text-gray-100">
                                                                    ₹ {p.price.toLocaleString('en-IN')}
                                                                </h3>
                                                                <div className="flex items-center gap-1.5 text-[10px] sm:text-xs font-semibold text-primary uppercase">
                                                                    {p.type} • {p.category}
                                                                </div>
                                                            </div>

                                                            <div className="flex items-start text-xs text-muted-foreground gap-1.5 pt-1">
                                                                <MapPin className="h-3.5 w-3.5 text-gray-400 mt-0.5 flex-shrink-0" />
                                                                <span className="line-clamp-1 uppercase tracking-wide text-[10px] sm:text-[11px]">
                                                                    {p.location}, {p.district}
                                                                </span>
                                                            </div>
                                                        </div>

                                                        {/* Status & Share Row */}
                                                        <div className="mt-4 flex items-center justify-between pt-3 border-t border-gray-50 dark:border-gray-800/50">
                                                            <div className="flex items-center gap-2">
                                                                <div className="flex items-center gap-1 px-2 py-1 bg-pink-50 dark:bg-pink-900/20 rounded-md border border-pink-100 dark:border-pink-800 text-[10px] text-pink-600 font-bold">
                                                                    <Check className="h-3 w-3" />
                                                                    <span>{p.likes}</span>
                                                                </div>
                                                                <div
                                                                    className={cn(
                                                                        "flex items-center gap-1 px-2 py-1 rounded-md border text-[10px] cursor-pointer transition-colors font-bold",
                                                                        myLeads.filter(l => l.property_id === p.id && l.status === 'new').length > 0
                                                                            ? "bg-blue-50 border-blue-200 text-blue-600"
                                                                            : "bg-gray-50 dark:bg-gray-900 border-gray-100 dark:border-gray-800 text-muted-foreground hover:text-primary"
                                                                    )}
                                                                    onClick={() => setActiveTab('responses')}
                                                                >
                                                                    <MessageSquare className="h-3 w-3" />
                                                                    <span>{p.leadsCount}</span>
                                                                </div>
                                                            </div>

                                                            <Button
                                                                variant="outline"
                                                                size="sm"
                                                                className="h-8 text-[11px] px-3 rounded-md hover:bg-primary hover:text-white border-primary/20 text-primary flex items-center gap-1.5"
                                                                onClick={() => {
                                                                    const url = `${window.location.origin}/property/${p.id}`;
                                                                    navigator.clipboard.writeText(url);
                                                                    toast.success('Link copied!');
                                                                }}
                                                            >
                                                                <Share2 className="h-3.5 w-3.5" /> Share
                                                            </Button>
                                                        </div>
                                                    </div>
                                                </div>
                                                {/* Title below thumbnail and content */}
                                                <div className="mt-3 pt-3 border-t border-gray-50 dark:border-gray-800/50">
                                                    <h4 className="font-bold text-sm text-gray-800 dark:text-gray-200 line-clamp-1">
                                                        {p.title}
                                                    </h4>
                                                </div>
                                            </CardContent>
                                        </Card>
                                    ))}
                                </div>
                            )}
                        </div>
                    </div>
                )}

                {activeTab === 'subscription' && (
                    <div className="max-w-4xl mx-auto py-10 space-y-12">
                        <SubscriptionDashboard />

                        <Card className="border-none shadow-xl bg-white dark:bg-gray-900 overflow-hidden">
                            <CardHeader className="bg-primary/5 border-b border-primary/10">
                                <div className="flex items-center justify-between">
                                    <CardTitle className="text-xl font-bold flex items-center gap-2 text-primary">
                                        <Gift className="h-5 w-5" />
                                        Referral Rewards & History
                                    </CardTitle>
                                    <Badge variant="default" className="bg-primary text-white font-bold px-3">
                                        Total Earnings: ₹{broker?.referralEarnings || 0}
                                    </Badge>
                                </div>
                                <CardDescription>
                                    Track your successful referrals and subscription extensions.
                                    <span className="block mt-1 text-[10px] text-amber-600 font-medium italic">
                                        * Rewards and extensions are granted only after the referred broker is approved by the Admin.
                                    </span>
                                </CardDescription>
                            </CardHeader>
                            <CardContent className="p-0">
                                <div className="overflow-x-auto">
                                    <table className="w-full text-sm text-left">
                                        <thead className="bg-gray-50 dark:bg-gray-800/50 text-gray-500 font-bold uppercase text-[10px] tracking-widest">
                                            <tr>
                                                <th className="px-6 py-4">Referred Broker</th>
                                                <th className="px-6 py-4">Date</th>
                                                <th className="px-6 py-4">Status</th>
                                                <th className="px-6 py-4">Extension</th>
                                                <th className="px-6 py-4 text-right">Reward</th>
                                            </tr>
                                        </thead>
                                        <tbody className="divide-y divide-gray-100 dark:divide-gray-800">
                                            {referralStats.length === 0 ? (
                                                <tr>
                                                    <td colSpan={5} className="px-6 py-12 text-center text-muted-foreground italic">
                                                        No referrals found. Start sharing your ID to earn rewards!
                                                    </td>
                                                </tr>
                                            ) : (
                                                referralStats.map((ref, idx) => (
                                                    <tr key={idx} className="hover:bg-gray-50 dark:hover:bg-gray-800/30 transition-colors">
                                                        <td className="px-6 py-4">
                                                            <div className="font-bold text-gray-900 dark:text-gray-100">{ref.referred_person_name}</div>
                                                            <div className="text-[10px] text-muted-foreground">{ref.referred_contact}</div>
                                                        </td>
                                                        <td className="px-6 py-4 text-gray-600 dark:text-gray-400">
                                                            {new Date(ref.created_at).toLocaleDateString()}
                                                        </td>
                                                        <td className="px-6 py-4">
                                                            <Badge
                                                                variant={ref.admin_approval_status ? "success" : "secondary" as any}
                                                                className={ref.admin_approval_status ? "bg-green-100 text-green-700" : ""}
                                                            >
                                                                {ref.admin_approval_status ? 'Approved' : 'Pending'}
                                                            </Badge>
                                                        </td>
                                                        <td className="px-6 py-4">
                                                            {ref.reward_status === 'applied' ? (
                                                                <span className="flex items-center gap-1 text-green-600 font-bold text-[11px]">
                                                                    <Check className="h-3 w-3" /> 1 Month Added
                                                                </span>
                                                            ) : (
                                                                <span className="text-gray-400 text-[11px]">Waiting for approval</span>
                                                            )}
                                                        </td>
                                                        <td className="px-6 py-4 text-right font-black text-primary">
                                                            ₹{ref.reward_value}
                                                        </td>
                                                    </tr>
                                                ))
                                            )}
                                        </tbody>
                                    </table>
                                </div>
                            </CardContent>
                        </Card>
                    </div>
                )}

                {/* Delete Confirmation Modal */}
                <Modal
                    isOpen={isDeleteModalOpen}
                    onClose={() => setIsDeleteModalOpen(false)}
                    title="Delete Property"
                >
                    <div className="space-y-6">
                        <div className="p-4 bg-red-50 text-red-700 rounded-xl border border-red-100 flex gap-3 text-sm">
                            <Trash2 className="h-5 w-5 flex-shrink-0" />
                            <p>Are you sure you want to delete this property? <strong>This action cannot be undone</strong> and all data including images and likes will be permanently removed.</p>
                        </div>

                        <div className="flex gap-3 mt-8">
                            <Button
                                variant="outline"
                                className="flex-1"
                                onClick={() => setIsDeleteModalOpen(false)}
                                disabled={!!isDeleting}
                            >
                                Cancel
                            </Button>
                            <Button
                                variant="destructive"
                                className="flex-1 font-bold shadow-lg shadow-red-200"
                                onClick={() => propertyToDelete && handleDelete(propertyToDelete)}
                                disabled={!!isDeleting}
                            >
                                {isDeleting ? "Deleting..." : "Delete Permanently"}
                            </Button>
                        </div>
                    </div>
                </Modal>

                {activeTab === 'profile' && (
                    <div className="max-w-4xl space-y-8">
                        {/* Profile Header Card */}
                        <Card>
                            <CardContent className="pt-10">
                                <div className="flex flex-col md:flex-row items-center gap-8">
                                    <div className="relative group">
                                        <div className="h-32 w-32 rounded-full bg-blue-100 dark:bg-blue-900 border-4 border-white dark:border-gray-800 shadow-xl overflow-hidden flex items-center justify-center relative">
                                            {(user as any)?.avatarUrl ? (
                                                <img src={(user as any).avatarUrl} alt={(user as any)?.name} className="h-full w-full object-cover" />
                                            ) : (
                                                <UserIcon className="h-16 w-16 text-blue-400" />
                                            )}

                                            {isUploadingAvatar && (
                                                <div className="absolute inset-0 bg-black/40 flex items-center justify-center">
                                                    <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-white"></div>
                                                </div>
                                            )}
                                        </div>
                                        <label htmlFor="avatar-upload" className="absolute bottom-0 right-0 p-2 bg-primary text-white rounded-full shadow-lg cursor-pointer hover:bg-primary/90 transition-transform active:scale-95">
                                            <Camera className="h-5 w-5" />
                                            <input
                                                id="avatar-upload"
                                                type="file"
                                                className="hidden"
                                                accept="image/*"
                                                onChange={onAvatarUpload}
                                                disabled={isUploadingAvatar}
                                            />
                                        </label>
                                    </div>
                                    <div className="flex-1 text-center md:text-left space-y-2">
                                        <div className="flex flex-col md:flex-row items-center gap-3">
                                            <h2 className="text-3xl font-bold">{(user as any)?.name}</h2>
                                            <Badge variant="success" className="bg-green-100 text-green-700 hover:bg-green-100 border-none">
                                                Verified Broker
                                            </Badge>
                                        </div>
                                        <p className="text-muted-foreground flex items-center justify-center md:justify-start gap-2">
                                            <span className="font-medium text-foreground">Broker Code:</span> {broker?.broker_code}
                                        </p>
                                        <div className="flex flex-wrap justify-center md:justify-start gap-4 text-sm pt-2">
                                            <div className="flex items-center gap-2">
                                                <MapPin className="h-4 w-4 text-primary" />
                                                <span>{broker?.districts.join(', ')}</span>
                                            </div>
                                            <div className="flex items-center gap-2">
                                                <Clock className="h-4 w-4 text-primary" />
                                                <span>Joined {new Date(broker?.registeredAt || '').toLocaleDateString()}</span>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            </CardContent>
                        </Card>

                        {/* Profile Info Grid */}
                        <div className="grid md:grid-cols-2 gap-8">
                            <Card>
                                <CardHeader>
                                    <CardTitle>Professional Details</CardTitle>
                                    <CardDescription>Your information as visible to clients.</CardDescription>
                                </CardHeader>
                                <CardContent className="space-y-4">
                                    <div className="grid gap-1">
                                        <label className="text-xs font-semibold text-muted-foreground uppercase">Company Name</label>
                                        <div className="p-2 bg-muted/30 rounded border">{broker?.companyName || 'Not Set'}</div>
                                    </div>
                                    <div className="grid gap-1">
                                        <label className="text-xs font-semibold text-muted-foreground uppercase">Designation</label>
                                        <div className="p-2 bg-muted/30 rounded border">{broker?.designation || 'Not Set'}</div>
                                    </div>
                                    <div className="grid gap-1">
                                        <label className="text-xs font-semibold text-muted-foreground uppercase">RERA Number</label>
                                        <div className="p-2 bg-muted/30 rounded border">{broker?.reraNumber || 'Not Set'}</div>
                                    </div>
                                </CardContent>
                            </Card>

                            <Card>
                                <CardHeader>
                                    <CardTitle>Contact Information</CardTitle>
                                    <CardDescription>Details for business communication.</CardDescription>
                                </CardHeader>
                                <CardContent className="space-y-4">
                                    <div className="grid gap-1">
                                        <label className="text-xs font-semibold text-muted-foreground uppercase">Mobile Number</label>
                                        <div className="p-2 bg-muted/30 rounded border">{broker?.phone}</div>
                                    </div>
                                    <div className="grid gap-1">
                                        <label className="text-xs font-semibold text-muted-foreground uppercase">Email Address</label>
                                        <div className="p-2 bg-muted/30 rounded border">{broker?.email}</div>
                                    </div>
                                    <div className="pt-4">
                                        <Button variant="outline" className="w-full" disabled>
                                            Request Information Change
                                        </Button>
                                        <p className="text-[10px] text-center text-muted-foreground mt-2">
                                            Contract support to change verified contact details.
                                        </p>
                                    </div>
                                </CardContent>
                            </Card>
                        </div>
                    </div>
                )}

                <Modal isOpen={isAddModalOpen} onClose={() => setIsAddModalOpen(false)} title="Add New Property">
                    <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">

                        {/* 1. Structure Type */}
                        <div>
                            <label className="text-sm font-medium">Property Type</label>
                            <select
                                {...register('structureType')}
                                className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm"
                            >
                                <option value="Villa">Villa / Independent House</option>
                                <option value="Apartment">Apartment / Flat</option>
                                <option value="Farmhouse">Farmhouse</option>
                                <option value="Land">Land / Plot</option>
                                <option value="Commercial">Commercial (Office/Shop)</option>
                            </select>
                        </div>

                        {/* 2. Conditional Fields based on Structure */}

                        {/* Villa / Farmhouse Fields */}
                        {(structureType === 'Villa' || structureType === 'Farmhouse') && (
                            <div className="grid grid-cols-2 gap-4">
                                <div className="col-span-2">
                                    <label className="text-sm font-medium">Land Area (Sqft/Cents)</label>
                                    <Input type="number" {...register('landArea')} step="0.01" />
                                </div>
                            </div>
                        )}

                        {/* Apartment Fields */}
                        {structureType === 'Apartment' && (
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="text-sm font-medium">Floor Number (1-50)</label>
                                    <select {...register('floorNumber')} className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm">
                                        {[...Array(50)].map((_, i) => (
                                            <option key={i + 1} value={i + 1}>{i + 1}</option>
                                        ))}
                                    </select>
                                </div>
                                <div>
                                    <label className="text-sm font-medium">Floor Detail (Optional)</label>
                                    <Input {...register('floorDetail')} placeholder="e.g. 3rd Floor" />
                                </div>
                            </div>
                        )}

                        {/* Parking Details (For non-land types) */}
                        {structureType && structureType !== 'Land' && (
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="text-sm font-medium">Parking Spaces (0-10)</label>
                                    <select {...register('parkingSpaces')} className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm">
                                        {[...Array(11)].map((_, i) => (
                                            <option key={i} value={i}>{i}</option>
                                        ))}
                                    </select>
                                </div>
                                {Number(parkingSpaces) > 0 && (
                                    <div>
                                        <label className="text-sm font-medium">Parking Type</label>
                                        <select {...register('parkingType')} className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm">
                                            <option value="Covered">Covered</option>
                                            <option value="Open">Open</option>
                                            <option value="Open but Covered">Open but Covered</option>
                                            <option value="Common Parking">Common Parking</option>
                                        </select>
                                    </div>
                                )}
                            </div>
                        )}

                        {/* Dynamic Amenities */}
                        {structureType && (
                            <div className="space-y-2">
                                <label className="text-sm font-medium capitalize">Facilities & Amenities</label>
                                <AmenitySelector
                                    allAmenities={amenitiesConfig}
                                    selectedAmenities={watch('facilities') || []}
                                    onToggle={(amenity) => {
                                        const current = watch('facilities') || [];
                                        if (current.includes(amenity)) {
                                            setValue('facilities', current.filter(a => a !== amenity));
                                        } else {
                                            setValue('facilities', [...current, amenity]);
                                        }
                                    }}
                                    propertyType={structureType}
                                />
                            </div>
                        )}

                        {/* Land Fields */}
                        {structureType === 'Land' && (
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="text-sm font-medium">Category</label>
                                    <select {...register('category')} className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm">
                                        <option value="residential">Residential</option>
                                        <option value="commercial">Commercial</option>
                                    </select>
                                </div>
                                <div>
                                    <label className="text-sm font-medium">Total Area</label>
                                    <Input
                                        type="number"
                                        {...register('landArea')}
                                        placeholder="Sqft / Cents"
                                    />
                                </div>
                            </div>
                        )}

                        <div>
                            <label className="text-sm font-medium">Title</label>
                            <Input {...register('title')} placeholder="e.g. Luxury 3BHK Villa" />
                            {errors.title?.message && <p className="text-xs text-red-500">{errors.title.message}</p>}
                        </div>

                        <div>
                            <label className="text-sm font-medium">Description</label>
                            <textarea
                                {...register('description')}
                                className="flex min-h-[80px] w-full rounded-md border border-input bg-background px-3 py-2 text-sm ring-offset-background placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:cursor-not-allowed disabled:opacity-50"
                                placeholder="Write detailed description point by point..."
                            />
                            {errors.description?.message && <p className="text-xs text-red-500">{errors.description.message}</p>}
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="text-sm font-medium">District</label>
                                <select
                                    {...register('district')}
                                    className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm"
                                >
                                    <option value="">Select District</option>
                                    {DISTRICTS.map(d => (
                                        <option key={d} value={d}>{d}</option>
                                    ))}
                                </select>
                                {errors.district?.message && <p className="text-xs text-red-500">{errors.district.message}</p>}
                            </div>
                            <div>
                                <label className="text-sm font-medium">City</label>
                                <Input {...register('location')} placeholder="e.g. Manipal" />
                                {errors.location?.message && <p className="text-xs text-red-500">{errors.location.message}</p>}
                            </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div className="col-span-2">
                                <label className="text-sm font-medium">Local Area / Village (Optional)</label>
                                <Input {...register('village')} placeholder="e.g. Kadri" />
                                {errors.village?.message && <p className="text-xs text-red-500">{errors.village.message}</p>}
                            </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <label className="text-sm font-medium">Price (₹)</label>
                                <Input type="number" {...register('price')} />
                                <div className="flex items-center gap-2 py-1">
                                    <div className="h-[1px] flex-1 bg-border/50"></div>
                                    <span className="text-[10px] font-bold text-muted-foreground tracking-widest uppercase">OR</span>
                                    <div className="h-[1px] flex-1 bg-border/50"></div>
                                </div>
                                <div className="flex items-center gap-2">
                                    <input type="checkbox" {...register('hidePrice')} id="hidePriceAdd" className="h-4 w-4 rounded border-gray-300 text-primary focus:ring-primary" />
                                    <label htmlFor="hidePriceAdd" className="text-xs font-semibold text-gray-700 dark:text-gray-300 cursor-pointer">Call or Message for quote</label>
                                </div>
                                {errors.price?.message && <p className="text-xs text-red-500">{errors.price.message}</p>}
                            </div>
                            <div>
                                <label className="text-sm font-medium">Google Map Link (Optional)</label>
                                <Input {...register('googleMapLink')} placeholder="https://maps.google.com/..." />
                            </div>
                        </div>

                        {/* Hidden type field if structure selected automatically implies it, otherwise show it */}
                        {/* We keep type as separate for Sale/Rent decision */}
                        <div>
                            <label className="text-sm font-medium">Transaction Type</label>
                            <select {...register('type')} className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm">
                                <option value="sale">Sale</option>
                                <option value="rent">Rent</option>
                                <option value="lease">Lease</option>
                            </select>
                        </div>

                        <div>
                            <label className="text-sm font-medium">Property Photos (Max 3)</label>
                            <div className="mt-1 flex flex-col items-center justify-center rounded-lg border-2 border-dashed border-muted-foreground/25 p-4 transition-colors hover:border-muted-foreground/50">
                                <Input
                                    type="file"
                                    multiple
                                    accept="image/*"
                                    onChange={handleImageUpload}
                                    className="hidden"
                                    id="photo-upload"
                                    disabled={uploadedImages.length >= 3}
                                />
                                <label
                                    htmlFor="photo-upload"
                                    className={`flex flex-col items-center cursor-pointer ${uploadedImages.length >= 3 ? 'opacity-50 cursor-not-allowed' : ''}`}
                                >
                                    <Plus className="h-8 w-8 text-muted-foreground mb-2" />
                                    <span className="text-sm text-muted-foreground">Click to upload photos</span>
                                </label>
                            </div>
                            <p className="mt-2 text-[10px] text-muted-foreground">
                                * Please upload only low resolution images. Acceptable size: less than 500KB per image.
                            </p>
                            {uploadedImages.length > 0 && (
                                <div className="mt-3 flex gap-2 overflow-x-auto pb-2">
                                    {uploadedImages.map((img, idx) => (
                                        <div key={idx} className="relative h-16 w-16 flex-shrink-0 group">
                                            <img src={img} alt={`Preview ${idx}`} className="h-full w-full object-cover rounded-md border" />
                                            <button
                                                type="button"
                                                onClick={() => setUploadedImages(prev => prev.filter((_, i) => i !== idx))}
                                                className="absolute -top-1 -right-1 bg-red-500 text-white rounded-full h-4 w-4 flex items-center justify-center text-[10px] shadow-sm opacity-0 group-hover:opacity-100 transition-opacity"
                                            >
                                                ×
                                            </button>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                        <Button type="submit" className="w-full" disabled={isLoading || uploadedImages.length === 0}>
                            {isLoading ? "Processing..." : "List Property"}
                        </Button>
                    </form>
                </Modal>

                <Modal
                    isOpen={isEditModalOpen}
                    onClose={() => {
                        setIsEditModalOpen(false);
                        setSelectedProperty(null);
                    }}
                    title="Edit Property Listing"
                >
                    <form onSubmit={handleSubmit(async (data) => {
                        if (!selectedProperty || !user) return;
                        setIsLoading(true);
                        try {
                            const facilitiesArray = data.facilities || [];

                            const { error } = await supabase
                                .from('properties')
                                .update({
                                    title: data.title,
                                    description: data.description,
                                    price: data.price,
                                    district: data.district,
                                    location: data.location,
                                    village: data.village,
                                    type: data.type,
                                    category: (['Villa', 'Apartment', 'Farmhouse'].includes(data.structureType || '') && data.structureType !== 'Land') ? 'residential' : data.category,
                                    structure_type: data.structureType,
                                    land_area: data.landArea || null,
                                    floor_number: data.floorNumber || null,
                                    floor_detail: data.floorDetail,
                                    parking_spaces: data.parkingSpaces || 0,
                                    parking_type: data.parkingType,
                                    parking_allocated: data.parkingAllocated,
                                    facilities: facilitiesArray,
                                    google_map_link: data.googleMapLink,
                                    hide_price: data.hidePrice || false,
                                    images: uploadedImages,
                                    updated_at: new Date().toISOString()
                                })
                                .eq('id', selectedProperty.id);

                            if (error) throw error;

                            // Update local state
                            updateProperty(selectedProperty.id, {
                                ...selectedProperty,
                                title: data.title,
                                description: data.description,
                                price: data.price,
                                district: data.district,
                                location: data.location,
                                village: data.village,
                                type: data.type,
                                category: (['Villa', 'Apartment', 'Farmhouse'].includes(data.structureType || '') && data.structureType !== 'Land') ? 'residential' : data.category,
                                structureType: data.structureType,
                                landArea: data.landArea,
                                floorNumber: data.floorNumber,
                                floorDetail: data.floorDetail,
                                parkingSpaces: data.parkingSpaces,
                                parkingType: data.parkingType as any,
                                parkingAllocated: data.parkingAllocated,
                                facilities: facilitiesArray,
                                google_map_link: data.googleMapLink,
                                hidePrice: data.hidePrice,
                                images: uploadedImages,
                                updatedAt: new Date().toISOString()
                            } as any);

                            toast.success('Property updated successfully!');
                            setIsEditModalOpen(false);
                            setSelectedProperty(null);
                            reset();
                        } catch (error: any) {
                            console.error('Error updating property:', error);
                            toast.error(error.message || 'Failed to update property');
                        } finally {
                            setIsLoading(false);
                        }
                    }, (errors) => {
                        console.error('Validation Errors:', errors);
                        const fieldNames = Object.keys(errors).join(', ');
                        toast.error(`Please check these fields: ${fieldNames}`);
                    })} className="space-y-4">

                        {/* 1. Structure Type */}
                        <div>
                            <label className="text-sm font-medium">Property Type</label>
                            <select
                                {...register('structureType')}
                                className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm"
                            >
                                <option value="Villa">Villa / Independent House</option>
                                <option value="Apartment">Apartment / Flat</option>
                                <option value="Farmhouse">Farmhouse</option>
                                <option value="Land">Land / Plot</option>
                                <option value="Commercial">Commercial (Office/Shop)</option>
                            </select>
                        </div>

                        {/* 2. Conditional Fields based on Structure */}

                        {/* Villa / Farmhouse Fields */}
                        {(structureType === 'Villa' || structureType === 'Farmhouse') && (
                            <div className="grid grid-cols-2 gap-4">
                                <div className="col-span-2">
                                    <label className="text-sm font-medium">Land Area (Sqft/Cents)</label>
                                    <Input type="number" {...register('landArea')} step="0.01" />
                                    {errors.landArea?.message && <p className="text-xs text-red-500">{errors.landArea.message}</p>}
                                </div>
                            </div>
                        )}

                        {/* Apartment Fields */}
                        {structureType === 'Apartment' && (
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="text-sm font-medium">Floor Number (1-50)</label>
                                    <select {...register('floorNumber')} className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm">
                                        {[...Array(50)].map((_, i) => (
                                            <option key={i + 1} value={i + 1}>{i + 1}</option>
                                        ))}
                                    </select>
                                </div>
                                <div>
                                    <label className="text-sm font-medium">Floor Detail (Optional)</label>
                                    <Input {...register('floorDetail')} placeholder="e.g. 3rd Floor" />
                                </div>
                            </div>
                        )}

                        {/* Parking Details (For non-land types) */}
                        {structureType && structureType !== 'Land' && (
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="text-sm font-medium">Parking Spaces (0-10)</label>
                                    <select {...register('parkingSpaces')} className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm">
                                        {[...Array(11)].map((_, i) => (
                                            <option key={i} value={i}>{i}</option>
                                        ))}
                                    </select>
                                </div>
                                {Number(parkingSpaces) > 0 && (
                                    <div>
                                        <label className="text-sm font-medium">Parking Type</label>
                                        <select {...register('parkingType')} className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm">
                                            <option value="Covered">Covered</option>
                                            <option value="Open">Open</option>
                                            <option value="Open but Covered">Open but Covered</option>
                                            <option value="Common Parking">Common Parking</option>
                                        </select>
                                    </div>
                                )}
                            </div>
                        )}

                        {/* Dynamic Amenities */}
                        {structureType && (
                            <div className="space-y-2">
                                <label className="text-sm font-medium capitalize">Facilities & Amenities</label>
                                <AmenitySelector
                                    allAmenities={amenitiesConfig}
                                    selectedAmenities={watch('facilities') || []}
                                    onToggle={(amenity) => {
                                        const current = watch('facilities') || [];
                                        if (current.includes(amenity)) {
                                            setValue('facilities', current.filter(a => a !== amenity));
                                        } else {
                                            setValue('facilities', [...current, amenity]);
                                        }
                                    }}
                                    propertyType={structureType}
                                />
                            </div>
                        )}

                        {/* Land Fields */}
                        {structureType === 'Land' && (
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="text-sm font-medium">Category</label>
                                    <select {...register('category')} className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm">
                                        <option value="residential">Residential</option>
                                        <option value="commercial">Commercial</option>
                                    </select>
                                </div>
                                <div>
                                    <label className="text-sm font-medium">Total Area</label>
                                    <Input
                                        type="number"
                                        {...register('landArea')}
                                        placeholder="Sqft / Cents"
                                    />
                                </div>
                            </div>
                        )}

                        <div>
                            <label className="text-sm font-medium">Title</label>
                            <Input {...register('title')} placeholder="e.g. Luxury 3BHK Villa" />
                            {errors.title?.message && <p className="text-xs text-red-500">{errors.title.message}</p>}
                        </div>

                        <div>
                            <label className="text-sm font-medium">Description</label>
                            <textarea
                                {...register('description')}
                                className="flex min-h-[80px] w-full rounded-md border border-input bg-background px-3 py-2 text-sm ring-offset-background placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:cursor-not-allowed disabled:opacity-50"
                                placeholder="Write detailed description point by point..."
                            />
                            {errors.description?.message && <p className="text-xs text-red-500">{errors.description.message}</p>}
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="text-sm font-medium">District</label>
                                <select
                                    {...register('district')}
                                    className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm"
                                >
                                    <option value="">Select District</option>
                                    {DISTRICTS.map(d => (
                                        <option key={d} value={d}>{d}</option>
                                    ))}
                                </select>
                                {errors.district?.message && <p className="text-xs text-red-500">{errors.district.message}</p>}
                            </div>
                            <div>
                                <label className="text-sm font-medium">City</label>
                                <Input {...register('location')} placeholder="e.g. Manipal" />
                                {errors.location?.message && <p className="text-xs text-red-500">{errors.location.message}</p>}
                            </div>
                            <div className="col-span-2">
                                <label className="text-sm font-medium">Local Area / Village (Optional)</label>
                                <Input {...register('village')} placeholder="e.g. Kadri" />
                                {errors.village?.message && <p className="text-xs text-red-500">{errors.village.message}</p>}
                            </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <label className="text-sm font-medium">Price (₹)</label>
                                <Input type="number" {...register('price')} />
                                <div className="flex items-center gap-2 py-1">
                                    <div className="h-[1px] flex-1 bg-border/50"></div>
                                    <span className="text-[10px] font-bold text-muted-foreground tracking-widest uppercase">OR</span>
                                    <div className="h-[1px] flex-1 bg-border/50"></div>
                                </div>
                                <div className="flex items-center gap-2">
                                    <input type="checkbox" {...register('hidePrice')} id="hidePriceEdit" className="h-4 w-4 rounded border-gray-300 text-primary focus:ring-primary" />
                                    <label htmlFor="hidePriceEdit" className="text-xs font-semibold text-gray-700 dark:text-gray-300 cursor-pointer">Call or Message for quote</label>
                                </div>
                                {errors.price?.message && <p className="text-xs text-red-500">{errors.price.message}</p>}
                            </div>
                            <div>
                                <label className="text-sm font-medium">Google Map Link (Optional)</label>
                                <Input {...register('googleMapLink')} placeholder="https://maps.google.com/..." />
                                {errors.googleMapLink?.message && <p className="text-xs text-red-500">{errors.googleMapLink.message}</p>}
                            </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div className="flex flex-col gap-2">
                                <label className="text-sm font-medium">Transaction Type</label>
                                <select {...register('type')} className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm">
                                    <option value="sale">Sale</option>
                                    <option value="rent">Rent</option>
                                    <option value="lease">Lease</option>
                                </select>
                                {errors.type?.message && <p className="text-xs text-red-500">{errors.type.message}</p>}
                            </div>
                            <div className="flex flex-col gap-2">
                                <label className="text-sm font-medium">Photos (Max 3)</label>
                                <div className="flex gap-2">
                                    {uploadedImages.map((img, idx) => (
                                        <div key={idx} className="relative h-10 w-10 flex-shrink-0 group">
                                            <img src={img} alt={`Preview ${idx}`} className="h-full w-full object-cover rounded-md border" />
                                            <button
                                                type="button"
                                                onClick={() => setUploadedImages(prev => prev.filter((_, i) => i !== idx))}
                                                className="absolute -top-1 -right-1 bg-red-500 text-white rounded-full h-4 w-4 flex items-center justify-center text-[10px] shadow-sm"
                                            >×</button>
                                        </div>
                                    ))}
                                    {uploadedImages.length < 3 && (
                                        <Button
                                            type="button"
                                            variant="outline"
                                            size="icon"
                                            className="h-10 w-10 border-dashed"
                                            onClick={() => document.getElementById('edit-photo-upload')?.click()}
                                        >
                                            <Plus className="h-4 w-4" />
                                        </Button>
                                    )}
                                    <Input
                                        id="edit-photo-upload"
                                        type="file"
                                        multiple
                                        accept="image/*"
                                        onChange={handleImageUpload}
                                        className="hidden"
                                    />
                                </div>
                            </div>
                        </div>

                        <div className="pt-4 flex gap-3">
                            <Button
                                type="button"
                                variant="outline"
                                className="flex-1"
                                onClick={() => {
                                    setIsEditModalOpen(false);
                                    setSelectedProperty(null);
                                }}
                            >
                                Cancel
                            </Button>
                            <Button type="submit" className="flex-1" disabled={isLoading || uploadedImages.length === 0}>
                                {isLoading ? "Updating..." : "Save Changes"}
                            </Button>
                        </div>
                    </form>
                </Modal>
            </div>
        </div>
    );
}

'use client';

import { useState, useMemo, useEffect, useRef } from 'react';
import { useStore } from '@/lib/store';
import { Button } from '@/components/ui/Button';
import { Input } from '@/components/ui/Input';
import { Card, CardHeader, CardTitle, CardContent } from '@/components/ui/Card';
import { Send, User, Bot, X, Search, ChevronLeft, MessageSquare, Check, CheckCheck } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { Broker, ChatMessage } from '@/lib/types';
import { supabase } from '@/lib/supabaseClient';

interface ChatWindowProps {
    isOpen: boolean;
    onClose: () => void;
}

export function ChatWindow({ isOpen, onClose }: ChatWindowProps) {
    const { user, brokers, chatMessages, addChatMessage, fetchChatMessages } = useStore();
    const [message, setMessage] = useState('');
    const [searchQuery, setSearchQuery] = useState('');
    const [selectedUser, setSelectedUser] = useState<Broker | 'bot' | null>(null);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    };

    useEffect(() => {
        if (isOpen && user?.id) {
            fetchChatMessages(user.id);
        }
    }, [isOpen, user?.id, fetchChatMessages]);

    useEffect(() => {
        if (!user?.id) return;

        const channel = supabase
            .channel('chat_realtime')
            .on('postgres_changes', {
                event: 'INSERT',
                schema: 'public',
                table: 'chat_messages',
                filter: `receiver_id=eq.${user.id}`,
            }, (payload) => {
                const newMsg: ChatMessage = {
                    id: payload.new.id,
                    senderId: payload.new.sender_id,
                    receiverId: payload.new.receiver_id,
                    text: payload.new.text,
                    timestamp: payload.new.timestamp
                };
                // Only add if not already in state (to avoid double entry from local addChatMessage)
                addChatMessage(newMsg);
            })
            .subscribe();

        return () => {
            supabase.removeChannel(channel);
        };
    }, [user?.id, addChatMessage]);

    useEffect(() => {
        scrollToBottom();
    }, [chatMessages, selectedUser]);

    const filteredBrokers = useMemo(() => {
        if (!searchQuery.trim()) return brokers.filter(b => b.id !== user?.id).slice(0, 10);
        return brokers.filter(b =>
            (b.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
                b.id.toLowerCase().includes(searchQuery.toLowerCase())) &&
            b.id !== user?.id
        );
    }, [brokers, searchQuery, user]);

    const activeMessages = useMemo(() => {
        if (!selectedUser) return [];
        const targetId = selectedUser === 'bot' ? 'bot' : selectedUser.id;
        const myId = user?.id || 'anonymous';
        return chatMessages.filter(msg =>
            (msg.senderId === myId && msg.receiverId === targetId) ||
            (msg.senderId === targetId && msg.receiverId === myId)
        );
    }, [chatMessages, selectedUser, user]);

    const handleSend = async () => {
        if (!message.trim() || !selectedUser) return;

        const targetId = selectedUser === 'bot' ? 'bot' : selectedUser.id;
        const newMsg: ChatMessage = {
            id: `msg-${Date.now()}`,
            senderId: user?.id || 'anonymous',
            receiverId: targetId,
            text: message,
            timestamp: new Date().toISOString(),
        };

        await addChatMessage(newMsg);
        setMessage('');

        // Bot Logic
        if (targetId === 'bot') {
            const lowerMsg = message.toLowerCase();
            let botReply = "I'm still learning! How can I help you today?";

            if (lowerMsg.includes('hello') || lowerMsg.includes('hi')) {
                botReply = `Hello ${(user as any)?.name || 'there'}! I am your Property Dosti Assistant.`;
            } else if (lowerMsg.includes('qr') || lowerMsg.includes('code') || lowerMsg.includes('pay')) {
                botReply = 'You can find the payment QR code in your Dashboard under the "Membership & Rewards" section. Just scan it to pay the ₹100 fee!';
            } else if (lowerMsg.includes('subscription') || lowerMsg.includes('fee')) {
                botReply = 'Our subscription is ₹100/month after a 45-day free trial. You can pay via QR code in your dashboard!';
            } else if (lowerMsg.includes('renew') || lowerMsg.includes('extend')) {
                botReply = 'To renew your subscription: 1. Scan the QR code in your dashboard. 2. Pay ₹100. 3. Click the "Confirm Payment on WhatsApp" button to notify our admin!';
            } else if (lowerMsg.includes('referral') || lowerMsg.includes('earn')) {
                botReply = 'Invite friends using your unique code to earn 1 month of free subscription for every successful signup!';
            }

            setTimeout(() => {
                addChatMessage({
                    id: `msg-bot-${Date.now()}`,
                    senderId: 'bot',
                    receiverId: user?.id || 'anonymous',
                    text: botReply,
                    timestamp: new Date().toISOString(),
                });
            }, 800);
        }
    };

    return (
        <AnimatePresence>
            {isOpen && (
                <motion.div
                    initial={{ opacity: 0, y: 100, scale: 0.9 }}
                    animate={{ opacity: 1, y: 0, scale: 1 }}
                    exit={{ opacity: 0, y: 100, scale: 0.9 }}
                    className="fixed inset-0 sm:inset-auto sm:bottom-6 sm:right-6 z-[60] sm:w-[400px] sm:max-w-[calc(100vw-3rem)]"
                >
                    <Card className="border-primary/20 bg-background/95 backdrop-blur overflow-hidden flex flex-col h-full sm:h-[600px] sm:max-h-[calc(100vh-10rem)] shadow-2xl sm:rounded-2xl rounded-none">
                        <CardHeader className="flex flex-row items-center justify-between py-4 border-b bg-primary/10 shrink-0 px-4">
                            <div className="flex items-center gap-3">
                                {selectedUser && (
                                    <Button variant="ghost" size="icon" className="h-8 w-8 text-primary" onClick={() => setSelectedUser(null)}>
                                        <ChevronLeft className="h-5 w-5" />
                                    </Button>
                                )}
                                <div className="relative">
                                    <div className="h-10 w-10 rounded-full bg-primary/20 flex items-center justify-center border border-primary/20">
                                        {selectedUser === 'bot' ? (
                                            <Bot className="h-6 w-6 text-primary" />
                                        ) : selectedUser ? (
                                            <span className="font-bold text-primary">{(selectedUser as Broker).name[0].toUpperCase()}</span>
                                        ) : (
                                            <MessageSquare className="h-6 w-6 text-primary" />
                                        )}
                                    </div>
                                    {selectedUser === 'bot' && (
                                        <div className="absolute -bottom-0.5 -right-0.5 h-3.5 w-3.5 bg-green-500 rounded-full border-2 border-white dark:border-gray-900" />
                                    )}
                                </div>
                                <div className="flex flex-col">
                                    <CardTitle className="text-sm font-bold leading-none">
                                        {selectedUser === 'bot' ? 'Property Assistant' : (selectedUser as any)?.name || 'Property Dosti Chat'}
                                    </CardTitle>
                                    <span className="text-[10px] text-muted-foreground mt-1">
                                        {selectedUser === 'bot' ? 'Online' : selectedUser ? 'Broker' : 'Connect with others'}
                                    </span>
                                </div>
                            </div>
                            <Button variant="ghost" size="icon" className="h-9 w-9 text-muted-foreground hover:text-foreground" onClick={onClose}>
                                <X className="h-5 w-5" />
                            </Button>
                        </CardHeader>

                        <CardContent className="p-0 flex-1 flex flex-col overflow-hidden bg-[url('https://w0.peakpx.com/wallpaper/580/650/HD-wallpaper-whatsapp-bg-cool-whatsapp-original.jpg')] bg-repeat bg-[length:400px]">
                            <div className="absolute inset-0 bg-white/90 dark:bg-black/80 pointer-events-none" />

                            {!selectedUser ? (
                                <div className="relative p-4 flex flex-col h-full space-y-4 z-10">
                                    <div className="relative group">
                                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground transition-colors group-focus-within:text-primary" />
                                        <Input
                                            placeholder="Search by Name or User ID..."
                                            className="pl-10 h-11 bg-background/50 border-primary/10 rounded-xl focus-visible:ring-primary/20 transition-all font-medium"
                                            value={searchQuery}
                                            onChange={(e) => setSearchQuery(e.target.value)}
                                        />
                                    </div>

                                    <div className="flex-1 overflow-y-auto space-y-3 pr-1 custom-scrollbar">
                                        <div
                                            className="flex items-center gap-4 p-3 rounded-2xl hover:bg-primary/5 cursor-pointer transition-all border border-transparent hover:border-primary/10 bg-background/40"
                                            onClick={() => setSelectedUser('bot')}
                                        >
                                            <div className="h-12 w-12 rounded-full bg-primary/10 flex items-center justify-center border border-primary/10">
                                                <Bot className="h-7 w-7 text-primary" />
                                            </div>
                                            <div className="flex-1 min-w-0">
                                                <p className="font-bold text-sm">Property Assistant</p>
                                                <p className="text-xs text-muted-foreground truncate">I can help with subscriptions and renewals</p>
                                            </div>
                                            <div className="h-2 w-2 rounded-full bg-green-500" />
                                        </div>

                                        <div className="space-y-2">
                                            <p className="text-[10px] uppercase font-bold text-primary tracking-widest px-2 opacity-70">Active Brokers</p>
                                            {filteredBrokers.map(broker => (
                                                <div
                                                    key={broker.id}
                                                    className="flex items-center gap-4 p-3 rounded-2xl hover:bg-primary/5 cursor-pointer transition-all border border-transparent hover:border-primary/10 bg-background/40"
                                                    onClick={() => setSelectedUser(broker)}
                                                >
                                                    <div className="h-12 w-12 rounded-full bg-secondary flex items-center justify-center font-bold text-secondary-foreground">
                                                        {broker.name[0]}
                                                    </div>
                                                    <div className="flex-1 min-w-0">
                                                        <p className="font-bold text-sm truncate">{broker.name}</p>
                                                        <p className="text-[10px] font-mono text-muted-foreground truncate">{broker.id}</p>
                                                    </div>
                                                </div>
                                            ))}
                                            {searchQuery && filteredBrokers.length === 0 && (
                                                <div className="text-center py-10 opacity-50">
                                                    <Search className="h-10 w-10 mx-auto mb-2" />
                                                    <p className="text-xs">No users found.</p>
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                </div>
                            ) : (
                                <div className="relative flex-1 flex flex-col overflow-hidden z-10">
                                    <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar">
                                        {activeMessages.length === 0 && (
                                            <div className="text-center mt-10 space-y-2 px-8">
                                                <div className="bg-primary/5 p-4 rounded-2xl border border-primary/10 inline-block mb-4">
                                                    <MessageSquare className="h-8 w-8 text-primary mx-auto mb-2" />
                                                    <p className="text-xs font-medium text-primary">Encryption & Privacy</p>
                                                </div>
                                                <p className="text-[11px] text-muted-foreground leading-relaxed">
                                                    Messages are stored securely in our database. Start a conversation with {selectedUser === 'bot' ? 'our AI Assistant' : (selectedUser as Broker).name}.
                                                </p>
                                            </div>
                                        )}
                                        {activeMessages.map((msg) => {
                                            const isMe = user ? msg.senderId === user.id : msg.senderId === 'anonymous';
                                            return (
                                                <div
                                                    key={msg.id}
                                                    className={`flex ${isMe ? 'justify-end' : 'justify-start'}`}
                                                >
                                                    <div
                                                        className={`relative max-w-[85%] px-3 py-2 text-sm shadow-sm ${isMe
                                                            ? 'bg-primary text-white rounded-2xl rounded-tr-none'
                                                            : 'bg-background text-foreground rounded-2xl rounded-tl-none border border-border'
                                                            }`}
                                                    >
                                                        <p className="leading-relaxed">{msg.text}</p>
                                                        <div className={`flex items-center gap-1 mt-1 justify-end opacity-70 text-[9px]`}>
                                                            <span>{new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                                                            {isMe && <CheckCheck className="h-3 w-3" />}
                                                        </div>
                                                    </div>
                                                </div>
                                            );
                                        })}
                                        <div ref={messagesEndRef} />
                                    </div>

                                    <div className="p-4 border-t bg-background/80 backdrop-blur-md shrink-0">
                                        <div className="flex gap-2 items-center">
                                            <Input
                                                placeholder="Type a message..."
                                                value={message}
                                                onChange={(e) => setMessage(e.target.value)}
                                                onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                                                className="flex-1 h-11 bg-muted/30 border-none rounded-2xl focus-visible:ring-primary/20 transition-all font-medium"
                                            />
                                            <Button
                                                size="icon"
                                                onClick={handleSend}
                                                disabled={!message.trim()}
                                                className="h-11 w-11 rounded-full bg-primary hover:bg-primary/90 text-white shadow-lg active:scale-95 transition-all shrink-0"
                                            >
                                                <Send className="h-5 w-5" />
                                            </Button>
                                        </div>
                                    </div>
                                </div>
                            )}
                        </CardContent>
                    </Card>
                </motion.div>
            )}
        </AnimatePresence>
    );
}

